globalThis.__BQ = {"dnaCiftSarmal":{"ilkokul":{"kolay":[{"q":"DNA molekülünün şekli neye benzetilir?","steps":[{"t":"DNA nedir","a":"Kalıtım maddesi","d":"DNA, canlıların özelliklerini taşıyan ve nesilden nesile aktaran bir moleküldür. Hücrelerimizin içinde bulunur. Saç rengi, göz rengi gibi özellikler DNA tarafından belirlenir."},{"t":"Şekli","a":"Burulmuş merdiven","d":"DNA, iki ipliğin birbirine sarılmasıyla oluşur ve burulmuş bir merdivene benzer. Bu şekle çift sarmal denir. Merdivenin iki kenarı gibi iki iplik vardır."}],"ans":"Burulmuş (sarmal) bir merdivene benzer; bu şekle çift sarmal denir."},{"q":"DNA kaç iplikten (zincirden) oluşur?","steps":[{"t":"DNA yapısı","a":"İki iplik","d":"DNA tek bir iplik değil, iki ayrı iplikten oluşur. Bu iki iplik birbirine sarılmıştır. Bu yüzden DNA çift sarmal olarak adlandırılır."},{"t":"Sayı","a":"İki","d":"DNA molekülünde tam olarak iki iplik bulunur. İki iplik birbirini tamamlar ve merdivenin iki kenarını oluşturur. Bu iki iplik birbirine bağlıdır."}],"ans":"DNA iki iplikten (iki zincirden) oluşur."},{"q":"DNA molekülünün iki ipliği birbirinden ayrılırsa neye benzer?","steps":[{"t":"Bağlı durum","a":"Sarmal merdiven","d":"DNA normalde iki ipliği birbirine sarılı halde bulunur. Bu hali burulmuş bir merdivene benzer. İki iplik ortadan birbirine tutunur."},{"t":"Ayrılınca","a":"Açık merdiven","d":"İki iplik birbirinden ayrılırsa fermuarın açılması gibi olur. Her iplik tek başına kalır. Bu sayede DNA kopyalanabilir."}],"ans":"İki iplik açılınca fermuarın açılması gibi olur; her iplik tek başına kalır."},{"q":"DNA molekülünü oluşturan iki iplik nerede bulunur?","steps":[{"t":"Hücre","a":"Vücudun yapı taşı","d":"Canlıların vücudu çok küçük hücrelerden oluşur. Her hücrenin içinde DNA bulunur. Hücreler gözle görülemeyecek kadar küçüktür."},{"t":"Çekirdek","a":"DNA'nın yeri","d":"DNA, hücrenin çekirdeği denilen bölümünde bulunur. Çekirdek hücrenin yönetim merkezi gibidir. İki iplikli DNA burada korunur."}],"ans":"DNA, hücrenin çekirdeği içinde bulunur."},{"q":"DNA molekülünün iki ipliği birbirine nasıl tutunur?","steps":[{"t":"İki iplik","a":"Karşılıklı durur","d":"DNA'da iki iplik karşılıklı olarak durur. Merdivenin iki kenarı gibi yan yanadır. Ortada birbirlerine bağlanırlar."},{"t":"Basamaklar","a":"Bağlanma","d":"İki iplik ortadaki basamaklarla birbirine tutunur. Bu basamaklar merdivenin orta kısmı gibidir. Böylece iki iplik bir arada kalır."}],"ans":"İki iplik, ortadaki basamaklar (bağlar) ile birbirine tutunur."}],"zor":[{"q":"DNA molekülünü ilk kez açıklayan iki bilim insanı kimlerdir ve modelin adı nedir?","steps":[{"t":"Bilim insanları","a":"Watson ve Crick","d":"DNA'nın yapısını James Watson ve Francis Crick adlı iki bilim insanı açıklamıştır. Onlar DNA'nın iki iplikli olduğunu göstermiştir. Bu çok önemli bir buluştur."},{"t":"Model adı","a":"Çift sarmal modeli","d":"Bu iki bilim insanının açıkladığı modele çift sarmal modeli denir. Model, DNA'nın burulmuş merdiven şeklinde olduğunu gösterir. Bu model bütün dünyada kabul görmüştür."}],"ans":"Watson ve Crick açıklamıştır; modelin adı çift sarmal (Watson-Crick) modelidir."},{"q":"DNA bir merdivene benzetilirse, merdivenin kenarları ve basamakları neye karşılık gelir?","steps":[{"t":"Kenarlar","a":"İki iplik","d":"Merdivenin iki uzun kenarı DNA'nın iki ipliğine karşılık gelir. Bu kenarlar boyunca iplik uzanır. İki kenar birbirine paralel durur."},{"t":"Basamaklar","a":"Ortadaki bağlar","d":"Merdivenin basamakları ise iki ipliği birbirine bağlayan kısımlardır. Her basamak iki iplik arasında yer alır. Basamaklar düzenli aralıklarla dizilir."},{"t":"Birleşim","a":"Sarmal yapı","d":"Kenarlar ve basamaklar birlikte merdiveni oluşturur. Bu merdiven burulduğunda çift sarmal ortaya çıkar. Böylece DNA'nın gerçek şekli oluşur."}],"ans":"Kenarlar iki ipliğe, basamaklar ipliklerin arasındaki bağlara karşılık gelir."},{"q":"DNA molekülü neden bir fermuara benzetilebilir?","steps":[{"t":"Kapalı fermuar","a":"Bağlı iki iplik","d":"Kapalı bir fermuarın iki tarafı birbirine geçmiştir. DNA'da da iki iplik birbirine bağlıdır. İki iplik karşılıklı durur ve birbirini tutar."},{"t":"Açılma","a":"İpliklerin ayrılması","d":"Fermuar açıldığında iki taraf ayrılır. DNA da kopyalanırken iki ipliği ortadan ayrılır. Bu ayrılma fermuarın açılmasına çok benzer."},{"t":"Sonuç","a":"Kopyalanma","d":"İplikler ayrılınca her iplik kendi eşini yapabilir. Böylece DNA çoğalır. Fermuar benzetmesi bu olayı anlamayı kolaylaştırır."}],"ans":"İki ipliği fermuar gibi açılıp kapanabildiği ve ayrılabildiği için fermuara benzetilir."},{"q":"DNA'nın iki ipliği birbirinin aynısı mıdır yoksa birbirini tamamlar mı?","steps":[{"t":"İki iplik","a":"Karşılıklı","d":"DNA'da iki iplik karşılıklı olarak durur. Bir iplikteki her kısmın karşısında diğer iplikten bir kısım bulunur. Bu kısımlar düzenli olarak eşleşir."},{"t":"Eşleşme","a":"Tamamlama","d":"İki iplik birbirinin aynısı değildir; birbirini tamamlar. Bir ipliğin yapısı diğerinin yapısını belirler. Bu yüzden iplikler birbirine uyar."},{"t":"Önemi","a":"Kopyalama","d":"İplikler birbirini tamamladığı için bir iplik kaybolsa bile diğerinden yeniden yapılabilir. Bu özellik DNA'nın kopyalanmasını sağlar. Böylece bilgi korunur."}],"ans":"İki iplik birbirinin aynısı değildir; birbirini tamamlar (eşleşir)."},{"q":"DNA'nın çift sarmal yapısı canlılar için neden önemlidir?","steps":[{"t":"Bilgi taşıma","a":"Kalıtım","d":"DNA, canlının özelliklerini taşıyan bilgileri içinde tutar. İki iplikli yapı bu bilgileri korur. Böylece özellikler güvenle saklanır."},{"t":"Kopyalama","a":"Çoğalma","d":"İki iplik birbirinden ayrılarak DNA kolayca kopyalanabilir. Yeni hücreler için yeni DNA üretilir. Bu sayede canlılar büyüyüp çoğalır."},{"t":"Aktarma","a":"Nesil aktarımı","d":"DNA'daki bilgiler anne babadan yavruya aktarılır. Çift sarmal yapı bu aktarımı sağlam yapar. Böylece türler özelliklerini devam ettirir."}],"ans":"Bilgiyi güvenle saklayıp kopyalanmasını ve yavrulara aktarılmasını sağladığı için önemlidir."}]},"ortaokul":{"kolay":[{"q":"DNA'nın çift sarmal yapısında iki ipliği bir arada tutan bağ türü nedir?","steps":[{"t":"İki iplik","a":"Karşılıklı bazlar","d":"DNA'nın iki ipliği boyunca organik bazlar dizilmiştir. Karşılıklı iplikteki bazlar birbirine yaklaşır. Bu bazlar arasında bir bağlantı kurulur."},{"t":"Bağ türü","a":"Hidrojen bağı","d":"Karşılıklı bazlar arasında hidrojen bağları oluşur. Bu bağlar iki ipliği bir arada tutar. Hidrojen bağları tek tek zayıf olsa da hepsi birlikte güçlü bir tutunma sağlar."}],"ans":"İki ipliği bir arada tutan bağlar hidrojen bağlarıdır."},{"q":"DNA molekülünün dış kısmında (omurgasında) hangi yapılar bulunur?","steps":[{"t":"Omurga","a":"İpliğin dışı","d":"DNA ipliğinin dış kısmına omurga denir. Bu omurga merdivenin kenarlarını oluşturur. Omurga iplik boyunca uzanır."},{"t":"Yapısı","a":"Şeker ve fosfat","d":"Omurga, sırayla dizilmiş şeker ve fosfat gruplarından oluşur. Buna şeker-fosfat omurgası denir. Organik bazlar ise omurgadan içeriye doğru uzanır."}],"ans":"DNA'nın dış omurgası şeker (deoksiriboz) ve fosfat gruplarından oluşur."},{"q":"DNA'da adenin (A) bazı hangi bazla eşleşir?","steps":[{"t":"Baz eşleşmesi","a":"Kurallı eşleşme","d":"DNA'da bazlar gelişigüzel değil, belirli kurallara göre eşleşir. Her baz yalnızca belirli bir bazla karşılıklı gelir. Bu kurala baz eşleşmesi denir."},{"t":"A bazı","a":"A=T","d":"Adenin (A) her zaman timin (T) ile eşleşir. Bu eşleşme aralarındaki hidrojen bağlarıyla olur. Yani bir iplikte A varsa karşısında T bulunur."}],"ans":"Adenin (A) bazı timin (T) bazı ile eşleşir (A=T)."},{"q":"DNA'da guanin (G) bazı hangi bazla eşleşir?","steps":[{"t":"Eşleşme kuralı","a":"Belirli eşleşme","d":"DNA'daki bazlar her zaman belirli bir kurala göre eşleşir. Her bazın karşısında belirli bir baz bulunur. Bu eşleşme tüm canlılarda aynıdır."},{"t":"G bazı","a":"G≡C","d":"Guanin (G) her zaman sitozin (C) ile eşleşir. Aralarında hidrojen bağları kurulur. Yani bir iplikte G varsa karşısında C bulunur."}],"ans":"Guanin (G) bazı sitozin (C) bazı ile eşleşir (G≡C)."},{"q":"DNA'nın çift sarmal yapısını oluşturan iki iplik nasıl dizilmiştir?","steps":[{"t":"İki iplik","a":"Karşılıklı","d":"DNA'da iki iplik karşılıklı olarak yer alır. İki iplik boyunca bazlar birbirine bakar. Karşılıklı bazlar eşleşerek bağ kurar."},{"t":"Sarmal","a":"Burulmuş hal","d":"Karşılıklı duran iki iplik birbirine sarılır. Bu sarılma sonucu çift sarmal şekil oluşur. Bu yüzden DNA burulmuş bir merdivene benzetilir."}],"ans":"İki iplik karşılıklı dizilir ve birbirine sarılarak çift sarmal oluşturur."}],"zor":[{"q":"Bir DNA ipliğindeki baz dizisi 5'-ATGC-3' ise karşı ipliğin baz dizisi nasıl olur?","steps":[{"t":"Eşleşme kuralı","a":"A=T, G≡C","d":"DNA'da adenin timin ile, guanin sitozin ile eşleşir. Her bazın karşısına eşi yazılır. Bu kurala tamamlayıcılık denir."},{"t":"Karşı bazlar","a":"TACG","d":"A karşısına T, T karşısına A, G karşısına C, C karşısına G gelir. Böylece karşı iplikte sırasıyla T, A, C, G oluşur. Bazlar tek tek eşlenir."},{"t":"Yön","a":"3'-TACG-5'","d":"İki iplik antiparalel dizildiği için yönler ters olur. Verilen iplik 5'-3' yönündeyse karşı iplik 3'-5' yönündedir. Karşı iplik 3'-TACG-5' biçiminde yazılır."}],"ans":"Karşı iplik 3'-TACG-5' (A=T, T=A, G≡C, C≡G eşleşmesiyle)."},{"q":"DNA'nın iki ipliğinin antiparalel olması ne anlama gelir?","steps":[{"t":"İplik yönü","a":"5' ve 3' uçları","d":"Her DNA ipliğinin iki ucu vardır; bunlara 5' ucu ve 3' ucu denir. Bu uçlar ipliğin yönünü belirler. Bilgi okuması bu yöne göre yapılır."},{"t":"Antiparalel","a":"Ters yön","d":"Antiparalel, iki ipliğin birbirine ters yönde uzanması demektir. Bir ipliğin 5' ucu karşısında diğer ipliğin 3' ucu bulunur. Yani iplikler zıt yönlerdedir."},{"t":"Önemi","a":"Düzenli eşleşme","d":"Antiparalel dizilim sayesinde bazlar düzgün şekilde eşleşebilir. İplikler ters yönde olduğu için hidrojen bağları doğru kurulur. Bu yapı çift sarmalın kararlılığını sağlar."}],"ans":"İki ipliğin birbirine ters yönde (biri 5'-3', diğeri 3'-5') uzanmasıdır."},{"q":"Adenin-timin (A=T) ile guanin-sitozin (G≡C) eşleşmeleri arasındaki hidrojen bağı sayısı farkı nedir?","steps":[{"t":"A=T bağı","a":"İki bağ","d":"Adenin ve timin arasında iki hidrojen bağı kurulur. Bu yüzden A=T şeklinde gösterilir. İki bağ olduğu için bu eşleşme nispeten daha zayıftır."},{"t":"G≡C bağı","a":"Üç bağ","d":"Guanin ve sitozin arasında üç hidrojen bağı kurulur. Bu yüzden G≡C şeklinde gösterilir. Üç bağ olduğu için bu eşleşme daha güçlüdür."},{"t":"Sonuç","a":"Bir bağ fark","d":"G≡C eşleşmesi A=T eşleşmesinden bir hidrojen bağı fazladır. G ve C oranı yüksek olan DNA daha kararlıdır. Bu fark DNA'nın çözülme sıcaklığını etkiler."}],"ans":"A=T iki, G≡C üç hidrojen bağı içerir; G≡C bir bağ fazladır ve daha güçlüdür."},{"q":"Bir DNA molekülünde 30 adenin (A) varsa, kaç timin (T) bulunur ve neden?","steps":[{"t":"Eşleşme","a":"A=T","d":"DNA'da adenin her zaman timin ile eşleşir. Her adeninin karşısında bir timin bulunur. Bu eşleşme tüm molekül boyunca geçerlidir."},{"t":"Sayı ilişkisi","a":"A = T","d":"Eşleşme kuralı gereği adenin sayısı timin sayısına eşittir. Bir baz arttığında karşı baz da artar. Bu kurala Chargaff kuralı denir."},{"t":"Sonuç","a":"30 timin","d":"Adenin sayısı 30 ise timin sayısı da 30 olur. Çünkü her A bir T ile eşleşir. Böylece A ve T sayıları daima eşittir."}],"ans":"30 timin bulunur; çünkü A=T eşleşmesi gereği adenin sayısı timin sayısına eşittir."},{"q":"DNA'nın şeker-fosfat omurgası ile organik bazlarının molekül içindeki konumları nasıldır?","steps":[{"t":"Omurga","a":"Dışta","d":"Şeker ve fosfat grupları molekülün dış kısmında yer alır. Bunlar merdivenin iki kenarını oluşturur. Omurga iplik boyunca düzenli olarak uzanır."},{"t":"Bazlar","a":"İçte","d":"Organik bazlar molekülün iç kısmında, karşılıklı iplikler arasında bulunur. Bazlar merdivenin basamaklarını oluşturur. İçeride birbirleriyle hidrojen bağı yapar."},{"t":"Genel yapı","a":"Dış omurga - iç bazlar","d":"Sonuç olarak omurga dışta, bazlar içtedir. Bu düzen çift sarmalın kararlı olmasını sağlar. Bazlar dış etkilerden omurga tarafından korunur."}],"ans":"Şeker-fosfat omurgası dışta, organik bazlar (basamaklar) içte bulunur."}]},"lise":{"kolay":[{"q":"DNA çift sarmalının iki ipliğini boylamasına tutan ve enine tutan bağlar hangileridir?","steps":[{"t":"Boylamasına","a":"Fosfodiester bağı","d":"Bir iplik boyunca nükleotitleri birbirine fosfodiester bağları bağlar. Bu bağlar şeker ve fosfat arasında kurulur. Omurgayı boylamasına sağlam tutar."},{"t":"Enine","a":"Hidrojen bağı","d":"İki ipliği enine olarak karşılıklı bazlar arasındaki hidrojen bağları tutar. Bu bağlar A=T ve G≡C arasında oluşur. İki ipliği bir arada tutan asıl bağ budur."},{"t":"Karşılaştırma","a":"Güçlü-zayıf","d":"Fosfodiester bağları kovalent ve güçlüdür, omurgayı korur. Hidrojen bağları zayıftır, böylece replikasyonda iplikler kolayca ayrılabilir. İki bağ türü farklı görev üstlenir."}],"ans":"Boylamasına fosfodiester bağları, enine ise hidrojen bağları tutar."},{"q":"DNA ipliğinde 5' ucu ve 3' ucu hangi kimyasal gruplarla belirlenir?","steps":[{"t":"5' ucu","a":"Fosfat grubu","d":"5' ucu, deoksiriboz şekerinin 5 numaralı karbonuna bağlı serbest fosfat grubunu taşır. Bu uç ipliğin bir başlangıcını gösterir. Yeni nükleotitler genelde 3' uca eklenir."},{"t":"3' ucu","a":"Hidroksil grubu","d":"3' ucu, deoksiribozun 3 numaralı karbonuna bağlı serbest hidroksil (-OH) grubunu taşır. Bu uç ipliğin diğer ucudur. Replikasyonda büyüme bu uçtan olur."},{"t":"Yön","a":"5'→3'","d":"İpliğin yönü 5' uçtan 3' uca doğru tanımlanır. Bu yön bilgi okumada ve sentezde önemlidir. İki iplik antiparalel olduğundan uçları terstir."}],"ans":"5' ucu serbest fosfat grubu, 3' ucu serbest hidroksil (-OH) grubu ile belirlenir."},{"q":"Chargaff kurallarına göre DNA'da baz oranları arasında hangi eşitlikler vardır?","steps":[{"t":"A ve T","a":"A = T","d":"Chargaff kuralına göre adenin miktarı timin miktarına eşittir. Çünkü her A bir T ile eşleşir. Bu eşitlik çift sarmaldaki baz eşleşmesinin sonucudur."},{"t":"G ve C","a":"G = C","d":"Aynı şekilde guanin miktarı sitozin miktarına eşittir. Her G bir C ile eşleşir. Böylece bu iki baz da eşit orandadır."},{"t":"Pürin-pirimidin","a":"A+G = T+C","d":"Pürin bazları (A+G) toplamı pirimidin bazları (T+C) toplamına eşittir. Her pürin karşısında bir pirimidin bulunur. Bu da çift sarmalın simetrisini gösterir."}],"ans":"A = T, G = C ve pürinler toplamı pirimidinler toplamına eşittir (A+G = T+C)."},{"q":"DNA'da pürin ve pirimidin bazları hangileridir ve eşleşmede neden bir pürin bir pirimidinle birleşir?","steps":[{"t":"Pürinler","a":"A ve G","d":"Adenin ve guanin çift halkalı yapıya sahip pürin bazlarıdır. Daha büyük moleküllerdir. İki azotlu halka içerirler."},{"t":"Pirimidinler","a":"T ve C","d":"Timin ve sitozin tek halkalı yapıya sahip pirimidin bazlarıdır. Daha küçük moleküllerdir. Tek azotlu halka içerirler."},{"t":"Eşleşme nedeni","a":"Sabit genişlik","d":"Bir pürin (büyük) bir pirimidin (küçük) ile eşleşir. Böylece iplikler arası mesafe her zaman sabit kalır. Bu da çift sarmalın düzgün ve kararlı olmasını sağlar."}],"ans":"Pürinler A ve G, pirimidinler T ve C'dir; büyük-küçük eşleşmesi sarmal genişliğini sabit tutar."},{"q":"Watson ve Crick'in çift sarmal modelini geliştirirken yararlandığı X ışını kırınım verisi kime aittir?","steps":[{"t":"X ışını çalışması","a":"Kristalografi","d":"DNA'nın yapısını çözmek için X ışını kırınım yöntemi kullanılmıştır. Bu yöntemle DNA'nın sarmal olduğu görüntülenmiştir. Görüntüler modelin kurulmasına yardımcı olmuştur."},{"t":"Veri sahibi","a":"Franklin ve Wilkins","d":"Bu görüntüler Rosalind Franklin ve Maurice Wilkins tarafından elde edilmiştir. Özellikle Franklin'in \"Fotoğraf 51\" adlı görüntüsü kritik olmuştur. Bu veri sarmal yapıyı kanıtlamıştır."},{"t":"Katkı","a":"Modelin kurulması","d":"Watson ve Crick bu verilerden yararlanarak çift sarmal modelini kurmuştur. X ışını verisi modelin doğruluğunu desteklemiştir. Böylece DNA'nın gerçek yapısı ortaya konmuştur."}],"ans":"X ışını kırınım verileri Rosalind Franklin ve Maurice Wilkins'e aittir (özellikle Fotoğraf 51)."},{"q":"DNA çift sarmalında bir iplikteki nükleotitleri birbirine bağlayan fosfodiester bağı hangi gruplar arasında kurulur?","steps":[{"t":"Bağlanma noktaları","a":"Şeker ve fosfat","d":"Fosfodiester bağı, bir nükleotidin şekeri ile komşu nükleotidin fosfatı arasında kurulur. Bu bağ omurgayı oluşturur. Nükleotitleri zincir halinde dizer."},{"t":"Karbonlar","a":"3' ve 5'","d":"Bağ, bir şekerin 3' karbonu ile diğer nükleotidin 5' fosfatı arasında oluşur. Buna 3'-5' fosfodiester bağı denir. Bu nedenle iplik 5'-3' yönü kazanır."},{"t":"Sonuç","a":"Omurga","d":"Bu bağlar tekrarlanarak şeker-fosfat omurgasını meydana getirir. Omurga molekülün dış kısmında yer alır. Kovalent olduğu için omurga oldukça sağlamdır."}],"ans":"Bir nükleotidin şekerinin 3' karbonu ile komşu nükleotidin 5' fosfatı arasında kurulur."},{"q":"DNA molekülünde toplam baz sayısı 1000 ve adenin sayısı 200 ise guanin sayısı kaçtır?","steps":[{"t":"A ve T","a":"A=T=200","d":"Chargaff kuralına göre adenin sayısı timin sayısına eşittir. Adenin 200 ise timin de 200 olur. A+T toplamı 400 eder."},{"t":"Kalan bazlar","a":"G+C=600","d":"Toplam baz 1000'dir; A ve T toplamı 400'dür. Geriye kalan 600 baz guanin ve sitozindir. Yani G+C = 1000 − 400 = 600."},{"t":"G hesabı","a":"G=C=300","d":"Guanin sayısı sitozin sayısına eşittir (G=C). G+C toplamı 600 olduğundan her biri 300 olur. Dolayısıyla guanin sayısı 300'dür."}],"ans":"Guanin sayısı 300'dür."},{"q":"DNA çift sarmalının kararlılığını sağlayan iki ana etkileşim türü nedir?","steps":[{"t":"Hidrojen bağları","a":"Bazlar arası","d":"Karşılıklı bazlar arasındaki hidrojen bağları iki ipliği bir arada tutar. A=T iki, G≡C üç bağ yapar. Bu bağlar enine kararlılık sağlar."},{"t":"Baz istiflenmesi","a":"Hidrofobik etkileşim","d":"Üst üste dizilen bazlar arasında baz istiflenme (stacking) etkileşimleri oluşur. Bu etkileşimler bazların suyla temasını azaltır. Sarmalın iç kısmını kararlı hale getirir."},{"t":"Birlikte etki","a":"Sağlam yapı","d":"Hidrojen bağları ve baz istiflenmesi birlikte çift sarmalı kararlı kılar. İki etkileşim birbirini tamamlar. Böylece DNA dış etkilere dayanıklı olur."}],"ans":"Bazlar arası hidrojen bağları ve bazların üst üste istiflenme etkileşimleridir."},{"q":"B-DNA formunda bir tam sarmal dönüşte yaklaşık kaç baz çifti bulunur?","steps":[{"t":"B-DNA formu","a":"Yaygın form","d":"Hücrede en yaygın bulunan DNA formu B-DNA'dır. Sağ elli sarmal yapıdadır. Watson-Crick modeli bu forma dayanır."},{"t":"Dönüş başına","a":"Yaklaşık 10 baz çifti","d":"B-DNA'da sarmalın bir tam dönüşünde yaklaşık 10 baz çifti yer alır. Bu dönüş yaklaşık 3,4 nanometre uzunluğundadır. Bazlar arası mesafe yaklaşık 0,34 nanometredir."}],"ans":"B-DNA'da bir tam dönüşte yaklaşık 10 baz çifti bulunur."},{"q":"DNA'nın yüksek sıcaklıkta ipliklerinin ayrılması (denatürasyon) hangi bağların kırılmasıyla olur?","steps":[{"t":"Isıtma etkisi","a":"Bağların zayıflaması","d":"DNA çözeltisi ısıtıldığında ipliklerin tutunmasını sağlayan bağlar zayıflar. Belirli bir sıcaklıkta iki iplik ayrılır. Bu olaya denatürasyon denir."},{"t":"Kırılan bağ","a":"Hidrojen bağları","d":"Denatürasyonda kırılan bağlar bazlar arasındaki hidrojen bağlarıdır. Fosfodiester bağları (omurga) kırılmaz. Yani iplikler bütün kalır, sadece birbirinden ayrılır."},{"t":"G-C etkisi","a":"Yüksek erime sıcaklığı","d":"G≡C oranı yüksek DNA daha yüksek sıcaklıkta ayrılır. Çünkü G≡C üç hidrojen bağı içerir. Bu da DNA'yı daha kararlı yapar."}],"ans":"Bazlar arasındaki hidrojen bağlarının kırılmasıyla olur; omurga (fosfodiester) bozulmaz."},{"q":"DNA çift sarmalında \"tamamlayıcılık\" ilkesi ne anlama gelir ve neden önemlidir?","steps":[{"t":"Tamamlayıcılık","a":"Eşleşme kuralı","d":"Tamamlayıcılık, bir iplikteki baz dizisinin diğer iplikteki bazları belirlemesidir. A karşısına T, G karşısına C gelir. İki iplik birbirinin tamamlayıcısıdır."},{"t":"Bilgi yedeği","a":"İki kopya","d":"Tamamlayıcılık sayesinde bir iplikte bulunan bilgi diğer iplikte de örtük olarak bulunur. Bu, bilginin iki kez saklanması demektir. Bir iplik zarar görse diğeri kalıp olabilir."},{"t":"Replikasyon","a":"Doğru kopyalama","d":"Bu ilke replikasyonun temelidir. Her iplik kendi tamamlayıcısını kalıp alarak yeni iplik yaptırır. Böylece DNA doğru biçimde kopyalanır."}],"ans":"Her bazın belirli bir bazla eşleşmesidir (A-T, G-C); bilginin yedeklenip doğru kopyalanmasını sağlar."},{"q":"DNA çift sarmalında majör (büyük) oluk ve minör (küçük) oluk nasıl oluşur?","steps":[{"t":"Sarmal burulması","a":"Asimetrik yapı","d":"İki iplik birbirine sarılırken omurgalar her yerde eşit uzaklıkta olmaz. Bu asimetrik burulma sarmalın yüzeyinde girintiler bırakır. Bu girintilere oluk denir."},{"t":"İki oluk","a":"Majör ve minör","d":"Sarmal boyunca geniş bir majör oluk ve dar bir minör oluk oluşur. Bu oluklar bazların kenarlarını dışarıya açar. Genişlikleri birbirinden farklıdır."},{"t":"İşlevi","a":"Protein bağlanması","d":"Proteinler bu oluklardan DNA'daki baz dizisini tanır. Özellikle majör oluk daha fazla bilgi sunar. Böylece gen düzenleyici proteinler doğru bölgeye bağlanır."}],"ans":"İpliklerin asimetrik burulmasıyla oluşur; geniş majör ve dar minör oluk meydana gelir."},{"q":"DNA molekülünde sitozin oranı toplam bazların yüzde 20'si ise adenin oranı yüzde kaçtır?","steps":[{"t":"C ve G","a":"C=G=%20","d":"Chargaff kuralına göre sitozin oranı guanin oranına eşittir. Sitozin %20 ise guanin de %20'dir. Böylece G+C toplamı %40 olur."},{"t":"Kalan oran","a":"A+T=%60","d":"Tüm bazlar toplamı %100'dür. G+C %40 olduğuna göre A+T = %100 − %40 = %60'tır. Bu oran adenin ve timine aittir."},{"t":"A hesabı","a":"A=%30","d":"Adenin oranı timin oranına eşittir (A=T). A+T %60 olduğundan her biri %30 olur. Dolayısıyla adenin oranı %30'dur."}],"ans":"Adenin oranı yüzde 30'dur."},{"q":"DNA çift sarmalında bazların molekülün iç kısmında, omurganın dış kısmında olması neden avantajlıdır?","steps":[{"t":"Bazların konumu","a":"İçte korunma","d":"Organik bazlar sarmalın iç kısmında yer alır. Böylece su ve dış etkenlerden korunurlar. Bazların taşıdığı genetik bilgi zarar görmez."},{"t":"Omurga konumu","a":"Dışta hidrofilik","d":"Şeker-fosfat omurgası dışta yer alır ve suyla etkileşir. Fosfat grupları negatif yüklü ve suyu seven yapıdadır. Bu, DNA'nın sulu hücre içinde çözünür kalmasını sağlar."},{"t":"Sonuç","a":"Kararlı ve korunaklı","d":"Bu düzen hem bilgiyi korur hem de molekülü kararlı tutar. Bazlar içte istiflenerek ek kararlılık sağlar. Böylece DNA hücre ortamında dayanıklı olur."}],"ans":"Bilgiyi taşıyan bazlar içte korunurken, suyu seven omurga dışta molekülü çözünür ve kararlı tutar."},{"q":"DNA'nın çift sarmal yapısı, Watson-Crick modeli neden bir \"yarı korunumlu replikasyon\" mekanizmasını öngörür?","steps":[{"t":"İki iplik","a":"Birbirini tamamlar","d":"Çift sarmalda iki iplik birbirinin tamamlayıcısıdır. Bir ipliğin dizisi diğerini belirler. Bu nedenle her iplik bir kalıp olabilir."},{"t":"Ayrılma","a":"Kalıp iplikler","d":"Replikasyonda iki iplik ayrılır ve her biri kalıp görevi görür. Her kalıp üzerine yeni bir tamamlayıcı iplik sentezlenir. Böylece iki yeni çift sarmal oluşur."},{"t":"Yarı korunum","a":"Eski + yeni","d":"Oluşan her yeni DNA bir eski (kalıp) ve bir yeni iplik içerir. Bu yüzden mekanizmaya yarı korunumlu denir. Watson-Crick modeli yapısı gereği bunu öngörür."}],"ans":"İplikler tamamlayıcı olduğu için her biri kalıp olur; yeni DNA bir eski bir yeni iplik içerir (yarı korunumlu)."}],"zor":[{"q":"Bir DNA ipliği 5'-TACGGATC-3' ise tamamlayıcı ipliğin dizisini, yönüyle birlikte yazınız.","steps":[{"t":"Eşleşme","a":"A-T, G-C","d":"Her bazın tamamlayıcısı bellidir: A ile T, G ile C eşleşir. Verilen ipliğin her bazının karşısına eşi yazılır. Bu işlem baz baz yapılır."},{"t":"Bazların yazımı","a":"ATGCCTAG","d":"5'-TACGGATC-3' ipliğinin karşısına sırasıyla A, T, G, C, C, T, A, G gelir. Yani T→A, A→T, C→G, G→C, G→C, A→T, T→A, C→G. Bu tamamlayıcı baz dizisidir."},{"t":"Yön belirleme","a":"3'-ATGCCTAG-5'","d":"İplikler antiparalel olduğundan tamamlayıcı iplik ters yönde okunur. Verilen 5'-3' ise tamamlayıcı 3'-5' yönündedir. Tamamlayıcı iplik 3'-ATGCCTAG-5' olarak yazılır."}],"ans":"Tamamlayıcı iplik 3'-ATGCCTAG-5' biçimindedir."},{"q":"Bir DNA molekülünde 1500 nükleotit bulunuyor ve sitozin sayısı 300 ise toplam hidrojen bağı sayısını hesaplayınız.","steps":[{"t":"G ve C","a":"G=C=300","d":"Çift sarmalda guanin sayısı sitozin sayısına eşittir. Sitozin 300 ise guanin de 300'dür. G-C çifti sayısı 300'dür."},{"t":"A ve T","a":"A=T=225","d":"Toplam nükleotit 1500'dür. G+C toplamı 600 olduğundan A+T = 1500 − 600 = 900 olur. A=T olduğundan her biri 450, yani A-T çifti sayısı 450'dir. (450 A ve 450 T)"},{"t":"Hidrojen bağları","a":"A=T: 2, G≡C: 3","d":"A-T çiftleri 2'şer, G-C çiftleri 3'er hidrojen bağı yapar. A-T çifti sayısı 450, G-C çifti sayısı 300'dür. Toplam bağ = (450×2) + (300×3) = 900 + 900 = 1800."}],"ans":"Toplam hidrojen bağı sayısı 1800'dür."},{"q":"Meselson ve Stahl deneyi, çift sarmalın hangi replikasyon modelini doğrulamış ve diğer iki modeli (korunumlu, dağılımlı) nasıl elemiştir?","steps":[{"t":"Deney düzeneği","a":"Ağır ve hafif azot","d":"Bakteriler önce ağır azot (15N) içeren ortamda, sonra hafif azot (14N) içeren ortamda üretilmiştir. DNA'nın yoğunluğu santrifüjle ölçülmüştür. Böylece eski ve yeni DNA ayırt edilmiştir."},{"t":"İlk bölünme","a":"Ara yoğunluk","d":"Bir bölünmeden sonra DNA tek bir ara yoğunlukta toplanmıştır. Bu, her DNA'nın yarı ağır yarı hafif olduğunu gösterir. Korunumlu model ayrı iki bant öngördüğü için elenmiştir."},{"t":"İkinci bölünme","a":"Yarı korunumlu doğrulandı","d":"İkinci bölünmede biri ara biri hafif olmak üzere iki bant oluşmuştur. Bu sonuç yarı korunumlu modeli destekler. Dağılımlı model giderek hafifleyen tek bant öngördüğü için elenmiştir."}],"ans":"Yarı korunumlu modeli doğrulamış; ara yoğunluk korunumluyu, iki ayrı bant ise dağılımlı modeli elemiştir."},{"q":"Bir DNA ipliğinde pürin/pirimidin oranı tek iplik için 0,7 iken, çift sarmalın tamamı için bu oran neden her zaman 1'dir?","steps":[{"t":"Tek iplik","a":"Sınırlama yok","d":"Tek bir iplikte pürin (A+G) ve pirimidin (T+C) sayıları eşit olmak zorunda değildir. Diziye bağlı olarak bu oran 1'den farklı olabilir. Örneğin 0,7 olabilir."},{"t":"Çift sarmal","a":"Tamamlayıcı eşleşme","d":"Çift sarmalda her pürin karşısında bir pirimidin bulunur. A karşısında T, G karşısında C yer alır. Bir iplikteki her A diğer iplikte bir T, her G bir C yaratır."},{"t":"Oran 1","a":"A+G = T+C","d":"Tüm molekülde pürin toplamı (A+G) pirimidin toplamına (T+C) eşit olur. Çünkü eşleşme bunu zorunlu kılar. Dolayısıyla çift sarmal için pürin/pirimidin oranı her zaman 1'dir."}],"ans":"Tamamlayıcı eşleşme her pürini bir pirimidinle eşlediğinden tüm molekülde A+G = T+C olur; oran 1'dir."},{"q":"DNA çift sarmalında bazların antiparalel ve tamamlayıcı dizilmesi neden bir zorunluluktur, paralel olsaydı ne olurdu?","steps":[{"t":"Baz geometrisi","a":"Yönlü eşleşme","d":"A-T ve G-C eşleşmelerinde bazların hidrojen bağı yapan grupları belirli bir geometriye sahiptir. Bu gruplar ancak iplikler ters yönde olduğunda hizalanır. Yani eşleşme yöne bağlıdır."},{"t":"Paralel durum","a":"Bağlar kurulamaz","d":"İki iplik paralel (aynı yönde) olsaydı bazların hidrojen bağı grupları doğru karşı karşıya gelemezdi. Bağ uzaklıkları ve açıları uymazdı. Kararlı bir çift sarmal oluşamazdı."},{"t":"Antiparalel zorunluluk","a":"Kararlı sarmal","d":"Antiparalel dizilimde gruplar tam karşı karşıya gelir ve hidrojen bağları en uygun açıda kurulur. Bu da sarmalı kararlı kılar. Bu yüzden antiparalellik bir zorunluluktur."}],"ans":"Bazların hidrojen bağı geometrisi yalnızca antiparalel dizilimde uyar; paralel olsaydı kararlı bağlar kurulamazdı."},{"q":"Toplam baz çifti sayısı 2000 olan bir DNA'da A-T çiftleri yüzde 40 ise, fosfodiester bağı sayısını ve toplam hidrojen bağı sayısını hesaplayınız.","steps":[{"t":"Çift sayıları","a":"A-T 800, G-C 1200","d":"Toplam 2000 baz çiftinin %40'ı A-T çiftidir: 2000×0,40 = 800. Geriye kalan %60 G-C çiftidir: 2000×0,60 = 1200. Böylece çift türleri belirlenir."},{"t":"Hidrojen bağları","a":"5200 bağ","d":"A-T çiftleri 2, G-C çiftleri 3 hidrojen bağı yapar. Toplam = (800×2) + (1200×3) = 1600 + 3600 = 5200. Bu çift sarmaldaki toplam hidrojen bağı sayısıdır."},{"t":"Fosfodiester bağları","a":"3996 bağ","d":"2000 baz çifti toplam 4000 nükleotit demektir (her iplikte 2000). Bir iplikte n nükleotit (n−1) fosfodiester bağı içerir. İki iplik için (2000−1)×2 = 1999×2 = 3998 fosfodiester bağı bulunur."}],"ans":"Toplam hidrojen bağı 5200; fosfodiester bağı sayısı 3998'dir."},{"q":"DNA'nın erime sıcaklığı (Tm) ile G-C içeriği arasındaki ilişkiyi açıklayıp, A-T oranı yüksek bir bölgenin replikasyon başlangıcı için neden uygun olduğunu belirtiniz.","steps":[{"t":"Tm tanımı","a":"İpliklerin yarısı ayrılır","d":"Erime sıcaklığı (Tm), DNA ipliklerinin yarısının ayrıldığı sıcaklıktır. Bu sıcaklıkta hidrojen bağları yeterince zayıflar. Tm, DNA'nın kararlılığının bir ölçüsüdür."},{"t":"G-C etkisi","a":"Yüksek G-C, yüksek Tm","d":"G≡C çiftleri üç hidrojen bağı içerir, A=T çiftleri iki. G-C oranı arttıkça daha çok bağ olduğundan ipliklerin ayrılması için daha yüksek sıcaklık gerekir. Yani G-C içeriği yüksek DNA'nın Tm değeri yüksektir."},{"t":"Replikasyon başlangıcı","a":"A-T zengin bölge","d":"Replikasyon, ipliklerin ayrılmasıyla başlar. A-T zengin bölgeler daha az bağ içerdiğinden kolayca açılır. Bu yüzden replikasyon orijinleri genellikle A-T açısından zengindir."}],"ans":"G-C içeriği arttıkça Tm yükselir; A-T zengin bölgeler az bağ içerip kolay açıldığından replikasyon başlangıcı için uygundur."},{"q":"Bir DNA ipliğinde A:T:G:C oranları sırasıyla 2:3:4:1 olarak verilmişse, bu tek iplik için Chargaff kuralları neden geçerli değildir, ancak çift sarmal için nasıl sağlanır?","steps":[{"t":"Tek iplik oranı","a":"A≠T, G≠C","d":"Verilen ipliğte A:T = 2:3 ve G:C = 4:1'dir. Bu durumda A ile T, G ile C eşit değildir. Demek ki Chargaff kuralları tek iplik için sağlanmaz."},{"t":"Karşı iplik","a":"Tamamlayıcı oranlar","d":"Tamamlayıcı iplikte oranlar tersine döner: A karşısına T, G karşısına C gelir. Karşı iplikte A:T:G:C = 3:2:1:4 olur. Çünkü her baz tamamlayıcısına dönüşür."},{"t":"Çift sarmal toplamı","a":"A=T, G=C","d":"İki iplik birleştiğinde toplam A = 2+3 = 5, toplam T = 3+2 = 5 olur; A=T sağlanır. Aynı şekilde toplam G = 4+1 = 5, toplam C = 1+4 = 5 olur; G=C sağlanır. Böylece Chargaff kuralları yalnızca çift sarmal için geçerlidir."}],"ans":"Tek iplikte A≠T, G≠C olduğundan kural geçmez; karşı iplikle toplandığında A=T ve G=C sağlandığı için çift sarmalda geçerlidir."},{"q":"DNA çift sarmalının çapı boyunca her baz çiftinin yaklaşık aynı genişlikte olması nasıl sağlanır ve iki pürin ya da iki pirimidin eşleşseydi ne olurdu?","steps":[{"t":"Sabit genişlik","a":"Pürin + pirimidin","d":"Her baz çifti bir pürin (büyük, çift halka) ve bir pirimidin (küçük, tek halka) içerir. Büyük ve küçük bazların toplam genişliği her çiftte yaklaşık aynıdır. Bu, sarmalın çapını sabit tutar."},{"t":"İki pürin durumu","a":"Çok geniş","d":"Eğer iki pürin (örneğin A-G) eşleşseydi, iki büyük halka yan yana gelirdi. Bu nokta normalden çok daha geniş olurdu. Sarmalda şişkinlik oluşurdu."},{"t":"İki pirimidin durumu","a":"Çok dar","d":"İki pirimidin (örneğin T-C) eşleşseydi, iki küçük halka yan yana gelir ve aralık çok daralırdı. İplikler birbirine yeterince yaklaşamaz, hidrojen bağları kurulamazdı. Sarmal düzensiz ve kararsız olurdu."}],"ans":"Her çift bir pürin bir pirimidin içerdiği için genişlik sabittir; iki pürin şişkinlik, iki pirimidin daralma yaratıp sarmalı bozardı."},{"q":"Bir DNA molekülünün bir ipliğinde 400 adenin, 350 timin, 300 guanin ve 250 sitozin vardır. Çift sarmalın tamamındaki her bir bazın sayısını bulunuz.","steps":[{"t":"Tamamlayıcı kuralı","a":"A↔T, G↔C","d":"İkinci iplikteki baz sayıları birinci ipliğin tamamlayıcısıdır. Birinci ipliğin A'sı kadar ikinci iplikte T, T'si kadar A bulunur. Aynı şekilde G ↔ C eşleşir."},{"t":"İkinci iplik","a":"A:350, T:400, G:250, C:300","d":"Birinci iplikte A=400 ise ikinci iplikte T=400, birinci iplikte T=350 ise ikinci iplikte A=350 olur. Birinci iplikte G=300 ise ikinci iplikte C=300, birinci iplikte C=250 ise ikinci iplikte G=250 olur. Böylece ikinci iplik bulunur."},{"t":"Toplam","a":"A=T=750, G=C=550","d":"Toplam A = 400 + 350 = 750, toplam T = 350 + 400 = 750'dir; A=T sağlanır. Toplam G = 300 + 250 = 550, toplam C = 250 + 300 = 550'dir; G=C sağlanır. Görüldüğü gibi tüm molekülde A=T ve G=C'dir."}],"ans":"Tüm molekülde A=750, T=750, G=550, C=550'dir."},{"q":"DNA çift sarmalının antiparalel yapısı, replikasyon sırasında öncü (leading) ve gecikmeli (lagging) iplik kavramlarını nasıl gerektirir?","steps":[{"t":"Sentez yönü","a":"Yalnızca 5'→3'","d":"DNA polimeraz enzimi yeni ipliği yalnızca 5'→3' yönünde sentezler. Yeni nükleotitleri 3' uca ekler. Bu yön zorunludur ve tersine işleyemez."},{"t":"Antiparalel kalıp","a":"Ters yönlü iki kalıp","d":"İki kalıp iplik antiparalel olduğundan biri 3'→5', diğeri 5'→3' yönündedir. Replikasyon çatalı tek yöne ilerlerken iki kalıp ters yöne bakar. Bu nedenle iki iplik aynı şekilde okunamaz."},{"t":"İki iplik tipi","a":"Öncü ve gecikmeli","d":"3'→5' kalıp üzerinde yeni iplik çatalla aynı yönde sürekli sentezlenir; buna öncü iplik denir. Diğer kalıpta sentez çatala ters yönde, kısa Okazaki parçaları halinde olur; buna gecikmeli iplik denir. Bu ayrım antiparalel yapının doğrudan sonucudur."}],"ans":"Polimeraz yalnızca 5'→3' sentezlediğinden, antiparalel kalıplardan biri sürekli (öncü), diğeri kesikli (gecikmeli) sentezlenir."},{"q":"B-DNA, A-DNA ve Z-DNA formları çift sarmal yapı açısından hangi temel özellikleriyle ayrılır?","steps":[{"t":"B-DNA","a":"Sağ elli, yaygın","d":"B-DNA hücrede en yaygın bulunan formdur ve sağ elli sarmaldır. Bir dönüşte yaklaşık 10 baz çifti vardır. Watson-Crick modeli bu forma dayanır."},{"t":"A-DNA","a":"Sağ elli, sıkı","d":"A-DNA da sağ elli sarmaldır ancak daha sıkı ve geniş bir yapıdadır. Su miktarı az olan koşullarda görülür. Bir dönüşte yaklaşık 11 baz çifti bulunur ve bazlar eksene eğiktir."},{"t":"Z-DNA","a":"Sol elli, zikzak","d":"Z-DNA sol elli sarmaldır ve omurgası zikzak şeklindedir. Genellikle G-C tekrarlarının çok olduğu bölgelerde oluşur. Bir dönüşte yaklaşık 12 baz çifti yer alır."}],"ans":"B-DNA sağ elli/yaygın (~10 bç), A-DNA sağ elli/sıkı (~11 bç), Z-DNA sol elli/zikzak (~12 bç) yapıdadır."},{"q":"Bir gen bölgesinde A-T oranı yüzde 60 olan DNA ile yüzde 40 olan DNA karşılaştırıldığında, hangisinin denatürasyonu daha kolaydır ve nükleotit başına ortalama hidrojen bağı hangisinde fazladır?","steps":[{"t":"Baz oranları","a":"İlki A-T zengin","d":"Birinci DNA'da A-T %60, G-C %40'tır. İkinci DNA'da A-T %40, G-C %60'tır. İkinci DNA daha fazla G-C içerir."},{"t":"Denatürasyon","a":"A-T zengin daha kolay","d":"A-T çiftleri 2 hidrojen bağı içerir, G-C çiftleri 3. A-T oranı yüksek olan birinci DNA daha az bağ içerir. Bu yüzden birinci DNA daha düşük sıcaklıkta, daha kolay denatüre olur."},{"t":"Ortalama bağ","a":"G-C zengin daha fazla","d":"Nükleotit başına ortalama hidrojen bağı G-C içeriğine bağlıdır. İkinci DNA daha çok G-C içerdiğinden ortalama bağ sayısı daha yüksektir. Yani ikinci DNA hem daha kararlı hem de baz başına daha çok bağ taşır."}],"ans":"A-T oranı %60 olan DNA daha kolay denatüre olur; baz başına ortalama hidrojen bağı G-C zengin (%40 A-T) olanda daha fazladır."},{"q":"DNA çift sarmalında bir bazda meydana gelen tautomerik değişim, baz eşleşmesini ve dolayısıyla replikasyon doğruluğunu nasıl etkileyebilir?","steps":[{"t":"Tautomerik form","a":"Nadir baz hali","d":"Bazlar genellikle kararlı (yaygın) bir formda bulunur. Ancak nadiren tautomer denilen farklı bir form alabilirler. Bu formda bazın hidrojen atomlarının konumu değişir."},{"t":"Yanlış eşleşme","a":"Hatalı baz çifti","d":"Tautomerik formdaki bir baz, normalde eşleşmediği bir bazla hidrojen bağı kurabilir. Örneğin nadir formdaki timin, adenin yerine guaninle eşleşebilir. Böylece yanlış bir baz çifti oluşur."},{"t":"Replikasyona etkisi","a":"Nokta mutasyonu","d":"Replikasyon sırasında bu yanlış eşleşme yeni ipliğe yanlış baz yerleştirilmesine yol açar. Tamir edilmezse bu hata nokta mutasyonu olarak kalıcılaşır. Böylece genetik bilgi değişebilir."}],"ans":"Tautomerik form yanlış baz eşleşmesine yol açar; replikasyonda yanlış baz yerleşip tamir edilmezse nokta mutasyonu oluşur."},{"q":"Çift sarmalın \"tamamlayıcı ve antiparalel\" olması, DNA tamir mekanizmalarının hasarlı bir bölgeyi neden doğru biçimde onarabilmesini sağlar?","steps":[{"t":"İki kopya bilgi","a":"Tamamlayıcılık","d":"Çift sarmalda her iplik diğerinin tamamlayıcısıdır. Bir iplikteki bilgi diğer iplikte de örtük olarak bulunur. Yani bilgi iki kez saklanır."},{"t":"Sağlam kalıp","a":"Hasarsız iplik","d":"Bir iplikte hasar olduğunda karşı iplik çoğunlukla sağlam kalır. Tamir enzimleri hasarlı kısmı çıkarır. Sağlam ipliği kalıp alarak eksik bölgeyi yeniden sentezler."},{"t":"Antiparalel sentez","a":"Doğru yön","d":"Antiparalel yapı, polimeraz enziminin sağlam kalıbı 5'→3' yönünde okumasına olanak verir. Tamamlayıcılık kuralı sayesinde doğru bazlar yerleştirilir. Böylece hasarlı bölge orijinaline uygun şekilde onarılır."}],"ans":"Sağlam tamamlayıcı iplik kalıp olur, antiparalel yapı doğru yönde sentezi sağlar; böylece hasar orijinaline uygun onarılır."}]}},"nukleotit":{"ilkokul":{"kolay":[{"q":"DNA'nın yapı birimine (yapı taşına) ne ad verilir?","steps":[{"t":"Yapı taşı","a":"Küçük birim","d":"Büyük moleküller küçük birimlerin birleşmesiyle oluşur. DNA da küçük birimlerden yapılmıştır. Bu küçük birimler arka arkaya dizilir."},{"t":"Adı","a":"Nükleotit","d":"DNA'nın yapı birimine nükleotit denir. Çok sayıda nükleotit birleşerek DNA'yı oluşturur. Yani nükleotitler DNA'nın tuğlaları gibidir."}],"ans":"DNA'nın yapı birimine nükleotit denir."},{"q":"Bir nükleotitte bulunan organik bazların adları nelerdir?","steps":[{"t":"Baz nedir","a":"Nükleotit parçası","d":"Her nükleotitin içinde bir organik baz bulunur. Baz, nükleotitin önemli bir parçasıdır. Bazlar harflerle gösterilir."},{"t":"Baz çeşitleri","a":"A, T, G, C","d":"DNA'da dört çeşit baz vardır: adenin (A), timin (T), guanin (G) ve sitozin (C). Her nükleotit bu bazlardan birini taşır. Bu dört baz DNA'nın harfleri gibidir."}],"ans":"Adenin (A), timin (T), guanin (G) ve sitozin (C)'dir."},{"q":"Bir nükleotit kaç temel parçadan oluşur?","steps":[{"t":"Nükleotit","a":"Yapı birimi","d":"Nükleotit DNA'nın yapı taşıdır. Kendi içinde bazı parçalar bulundurur. Bu parçalar birleşerek bir nükleotiti oluşturur."},{"t":"Parça sayısı","a":"Üç parça","d":"Bir nükleotit üç temel parçadan oluşur: fosfat, şeker ve organik baz. Bu üç parça bir araya gelir. Böylece tek bir nükleotit oluşur."}],"ans":"Bir nükleotit üç parçadan oluşur: fosfat, şeker ve organik baz."},{"q":"Nükleotitler birleşerek hangi büyük molekülü oluşturur?","steps":[{"t":"Tek nükleotit","a":"Yapı taşı","d":"Tek bir nükleotit DNA'nın küçük bir parçasıdır. Tek başına büyük bir molekül değildir. Asıl molekül için birçok nükleotit gerekir."},{"t":"Birleşme","a":"DNA oluşur","d":"Çok sayıda nükleotit arka arkaya bağlanır. Bu birleşme sonucu DNA molekülü oluşur. Yani nükleotitler dizilerek DNA'yı yapar."}],"ans":"Nükleotitler birleşerek DNA molekülünü oluşturur."},{"q":"Nükleotitin içindeki şeker hangi maddeye bağlanır?","steps":[{"t":"Şeker","a":"Orta parça","d":"Nükleotitin ortasında bir şeker bulunur. Bu şeker diğer parçaları birbirine bağlar. Şeker nükleotitin merkezindedir."},{"t":"Bağlanma","a":"Baz ve fosfat","d":"Şeker bir tarafından organik baza, diğer tarafından fosfata bağlanır. Böylece üç parça birbirine tutunur. Şeker köprü gibi davranır."}],"ans":"Nükleotitin şekeri bir yandan organik baza, diğer yandan fosfata bağlanır."}],"zor":[{"q":"DNA nükleotitinde bulunan şekerin adı nedir ve neden bu adı alır?","steps":[{"t":"Şeker","a":"Beş karbonlu","d":"DNA nükleotitinde beş karbonlu bir şeker bulunur. Bu şeker nükleotitin orta parçasıdır. Diğer parçaları birbirine bağlar."},{"t":"Adı","a":"Deoksiriboz","d":"Bu şekerin adı deoksiribozdur. \"Deoksi\" sözcüğü bir oksijenin eksik olduğunu anlatır. Bu yüzden DNA, deoksiribonükleik asit olarak adlandırılır."}],"ans":"DNA nükleotitindeki şekerin adı deoksiribozdur (beş karbonlu, bir oksijeni eksik şeker)."},{"q":"İki nükleotitin DNA ipliğinde birbirine bağlanması nasıl gerçekleşir?","steps":[{"t":"Bağlanma noktası","a":"Şeker ve fosfat","d":"Bir nükleotidin fosfatı, komşu nükleotidin şekerine bağlanır. Bu bağ nükleotitleri arka arkaya dizer. Böylece zincir uzar."},{"t":"Omurga","a":"Şeker-fosfat","d":"Bu bağlanmalar tekrarlandıkça şeker-fosfat omurgası oluşur. Omurga ipliğin uzun kenarı gibidir. Bazlar bu omurgadan içeriye doğru uzanır."}],"ans":"Bir nükleotidin fosfatı komşu nükleotidin şekerine bağlanarak şeker-fosfat zincirini oluşturur."},{"q":"Bir nükleotitin üç parçası birleşince nasıl bir düzen oluşur?","steps":[{"t":"Merkez","a":"Şeker","d":"Nükleotitin merkezinde şeker bulunur. Şeker diğer iki parçayı birbirine bağlar. Yapının orta noktasıdır."},{"t":"Bir yan","a":"Fosfat","d":"Şekerin bir tarafına fosfat grubu bağlanır. Fosfat ipliklerin dış kenarında yer alır. Komşu nükleotitle bağ kurmayı sağlar."},{"t":"Diğer yan","a":"Organik baz","d":"Şekerin diğer tarafına organik baz bağlanır. Baz ipliğin iç kısmına doğru uzanır. Karşı ipliğin bazıyla eşleşir."}],"ans":"Ortada şeker, bir yanında fosfat, diğer yanında organik baz bulunacak şekilde birleşir."},{"q":"DNA'da kaç çeşit nükleotit bulunur ve bu çeşitliliği ne sağlar?","steps":[{"t":"Ortak parçalar","a":"Şeker ve fosfat aynı","d":"DNA'daki tüm nükleotitlerde şeker (deoksiriboz) ve fosfat aynıdır. Bu iki parça değişmez. Yani nükleotitleri ayıran kısım bunlar değildir."},{"t":"Değişen parça","a":"Organik baz","d":"Nükleotitler taşıdıkları organik baza göre farklılık gösterir. DNA'da dört çeşit baz vardır: A, T, G, C. Her baz farklı bir nükleotit yapar."},{"t":"Çeşit sayısı","a":"Dört çeşit","d":"Dört farklı baz olduğu için DNA'da dört çeşit nükleotit bulunur. Çeşitliliği organik baz sağlar. Bu dört nükleotit farklı sıralarla genetik bilgiyi oluşturur."}],"ans":"DNA'da dört çeşit nükleotit bulunur; bu çeşitliliği taşıdıkları organik baz (A, T, G, C) sağlar."},{"q":"Bir nükleotitin parçalarından hangisi genetik bilgiyi belirler ve neden?","steps":[{"t":"Değişmeyen parçalar","a":"Şeker-fosfat","d":"Tüm nükleotitlerde şeker ve fosfat aynıdır. Bu parçalar omurgayı oluşturur ama bilgi taşımaz. Çünkü her nükleotitte aynıdırlar."},{"t":"Değişen parça","a":"Organik baz","d":"Nükleotitler arasındaki tek fark organik bazlarıdır. Bazlar dört çeşittir: A, T, G, C. Bu yüzden bilgiyi belirleyen kısım bazlardır."},{"t":"Bilgi","a":"Baz dizilimi","d":"Bazların iplik boyunca dizilme sırası genetik bilgiyi oluşturur. Farklı baz sıraları farklı bilgiler taşır. Bu yüzden genetik bilgiyi organik bazlar belirler."}],"ans":"Genetik bilgiyi organik baz belirler; çünkü şeker-fosfat değişmezken bazların dizilimi bilgiyi oluşturur."}]},"ortaokul":{"kolay":[{"q":"Bir DNA nükleotidini oluşturan üç bileşen nedir?","steps":[{"t":"Nükleotit","a":"Yapı birimi","d":"Nükleotit DNA'nın temel yapı birimidir. Üç farklı bileşenin birleşmesiyle oluşur. Bu bileşenler birbirine kimyasal bağlarla tutunur."},{"t":"Bileşenler","a":"Fosfat, şeker, baz","d":"Bir nükleotit fosfat grubu, deoksiriboz şekeri ve bir organik bazdan oluşur. Bu üçü birleşerek tek nükleotidi meydana getirir. Üç bileşen her DNA nükleotidinde bulunur."}],"ans":"Fosfat grubu, deoksiriboz şekeri ve organik baz."},{"q":"DNA ve RNA nükleotitlerinde bulunan şekerler arasındaki fark nedir?","steps":[{"t":"DNA şekeri","a":"Deoksiriboz","d":"DNA nükleotidinde deoksiriboz şekeri bulunur. Bu şekerde bir oksijen eksiktir. Adı buradan gelir."},{"t":"RNA şekeri","a":"Riboz","d":"RNA nükleotidinde ise riboz şekeri bulunur. Riboz, deoksiribozdan bir oksijen fazla içerir. Bu fark iki molekülü ayırır."}],"ans":"DNA'da deoksiriboz, RNA'da riboz şekeri bulunur; riboz bir oksijen fazla içerir."},{"q":"DNA ve RNA nükleotitlerinde hangi baz farklıdır?","steps":[{"t":"Ortak bazlar","a":"A, G, C","d":"Adenin, guanin ve sitozin bazları hem DNA'da hem RNA'da bulunur. Bu üç baz ortaktır. İki molekülde de yer alırlar."},{"t":"Farklı baz","a":"T yerine U","d":"DNA'da timin (T) bulunurken RNA'da timin yerine urasil (U) bulunur. Yani DNA'da T, RNA'da U vardır. Bu, iki molekül arasındaki baz farkıdır."}],"ans":"DNA'da timin (T), RNA'da onun yerine urasil (U) bulunur."},{"q":"Bir nükleotitte organik baz, şekerin neresine bağlanır?","steps":[{"t":"Şeker","a":"Merkez bileşen","d":"Deoksiriboz şekeri nükleotidin merkezindedir. Hem baza hem fosfata bağlanır. İki bileşeni birbirine bağlar."},{"t":"Bağlanma","a":"Baz şekere bağlı","d":"Organik baz, şekerin bir karbonuna bağlanır. Fosfat ise şekerin başka bir karbonuna bağlanır. Böylece üç bileşen düzenli olarak birleşir."}],"ans":"Organik baz, deoksiriboz şekerinin bir karbonuna bağlanır."},{"q":"Pürin ve pirimidin nükleotitleri arasındaki temel fark nedir?","steps":[{"t":"Pürinler","a":"Çift halkalı","d":"Adenin ve guanin pürin bazlarıdır. Bu bazlar çift halkalı (iki azotlu halka) yapıya sahiptir. Daha büyük moleküllerdir."},{"t":"Pirimidinler","a":"Tek halkalı","d":"Timin ve sitozin pirimidin bazlarıdır. Bu bazlar tek halkalı yapıya sahiptir. Daha küçük moleküllerdir."}],"ans":"Pürin bazları (A, G) çift halkalı ve büyük, pirimidin bazları (T, C) tek halkalı ve küçüktür."}],"zor":[{"q":"Bir nükleotidin fosfat grubu komşu nükleotitle nasıl bağ kurar ve bu bağ neyi oluşturur?","steps":[{"t":"Fosfat konumu","a":"Şekerin 5' karbonu","d":"Fosfat grubu, nükleotitteki şekerin 5' karbonuna bağlıdır. Bu konum bağlanma için önemlidir. Fosfat negatif yüklüdür."},{"t":"Komşu bağ","a":"Şekerin 3' karbonu","d":"Bir nükleotidin 5' fosfatı, komşu nükleotidin şekerinin 3' karbonuna bağlanır. Bu bağa fosfodiester bağı denir. Nükleotitleri arka arkaya dizer."},{"t":"Sonuç","a":"Şeker-fosfat omurgası","d":"Bu bağlar tekrarlanarak şeker-fosfat omurgasını oluşturur. Omurga ipliğin dış kenarını yapar. Organik bazlar ise içeriye doğru uzanır."}],"ans":"Bir nükleotidin 5' fosfatı komşunun 3' şekerine bağlanır (fosfodiester bağı) ve şeker-fosfat omurgasını oluşturur."},{"q":"DNA ve RNA nükleotitleri şeker ve baz açısından karşılaştırıldığında hangi iki temel fark görülür?","steps":[{"t":"Şeker farkı","a":"Deoksiriboz / riboz","d":"DNA nükleotidinde deoksiriboz, RNA nükleotidinde riboz bulunur. Riboz, deoksiribozdan bir oksijen (hidroksil) fazla içerir. Bu, iki molekülün ilk farkıdır."},{"t":"Baz farkı","a":"Timin / urasil","d":"DNA'da pirimidin bazı olarak timin, RNA'da timin yerine urasil bulunur. Adenin, guanin ve sitozin ortaktır. Timin-urasil farkı ikinci temel farktır."},{"t":"Sonuç","a":"İki ayırt edici özellik","d":"Böylece DNA ve RNA nükleotitleri hem şeker hem de bir baz bakımından farklıdır. Bu farklar iki molekülün işlevini de etkiler. DNA bilgi deposu, RNA ise daha çok aktarıcı görev yapar."}],"ans":"DNA deoksiriboz ve timin, RNA riboz ve urasil içerir; farklar şeker (deoksiriboz/riboz) ve baz (timin/urasil) açısındandır."},{"q":"Adenin nükleotidinin tamamlayıcı eşi hangi nükleotittir ve aralarındaki bağ kaç hidrojen bağı içerir?","steps":[{"t":"Adenin eşi","a":"Timin","d":"DNA'da adenin nükleotidi her zaman timin nükleotidi ile eşleşir. Bu eşleşme sabittir. A karşısında daima T bulunur."},{"t":"Bağ türü","a":"Hidrojen bağı","d":"Adenin ile timin arasında hidrojen bağları kurulur. Bu bağlar iki ipliği bir arada tutar. Bağ türü kovalent değil, daha zayıf hidrojen bağıdır."},{"t":"Bağ sayısı","a":"İki bağ","d":"Adenin ve timin arasında iki hidrojen bağı bulunur. Bu yüzden A=T şeklinde gösterilir. G≡C'ye göre daha az bağ içerdiğinden bu çift daha kolay ayrılır."}],"ans":"Adenin, timin nükleotidi ile eşleşir; aralarında iki hidrojen bağı bulunur (A=T)."},{"q":"Nükleotit ile nükleozit arasındaki fark nedir?","steps":[{"t":"Nükleozit","a":"Şeker + baz","d":"Nükleozit, sadece şeker ve organik bazdan oluşur. Fosfat grubu içermez. Yani iki bileşenlidir."},{"t":"Nükleotit","a":"Şeker + baz + fosfat","d":"Nükleotit ise şeker, baz ve fosfat grubunun hepsini içerir. Nükleozite bir fosfat eklenmesiyle oluşur. Yani üç bileşenlidir."},{"t":"Fark","a":"Fosfat varlığı","d":"İki yapı arasındaki tek fark fosfat grubudur. Fosfat eklenince nükleozit nükleotide dönüşür. DNA ve RNA nükleotitlerden oluşur."}],"ans":"Nükleozit şeker ve bazdan oluşur; nükleotit buna ek olarak fosfat grubu da içerir."},{"q":"Bir DNA ipliğinde 4 farklı nükleotit yalnızca 4 baz içermesine rağmen, sınırsız sayıda farklı genetik bilgi nasıl oluşturulabilir?","steps":[{"t":"Dört harf","a":"A, T, G, C","d":"DNA'da yalnızca dört çeşit nükleotit (baz) vardır. Bunlar A, T, G ve C'dir. Tek başlarına sınırlı görünürler."},{"t":"Dizilim","a":"Sıralama önemli","d":"Bu dört nükleotit iplik boyunca farklı sıralarda dizilebilir. Sıralamanın değişmesi taşınan bilgiyi değiştirir. Yani önemli olan harflerin sayısı değil, dizilme sırasıdır."},{"t":"Çeşitlilik","a":"Çok sayıda kombinasyon","d":"İplik uzadıkça olası dizilim sayısı katlanarak artar. Az sayıda harfle bile çok uzun ve farklı diziler kurulabilir. Bu yüzden dört nükleotit sınırsız genetik bilgi yaratabilir."}],"ans":"Dört nükleotidin iplik boyunca farklı sıralarda dizilmesi, az harfle sınırsız sayıda farklı bilgi oluşturmayı sağlar."}]},"lise":{"kolay":[{"q":"Bir DNA nükleotidinde fosfat, şeker ve baz hangi karbonlar üzerinden birbirine bağlanır?","steps":[{"t":"Baz bağı","a":"1' karbon","d":"Organik baz, deoksiriboz şekerinin 1' (bir üssü) karbonuna bağlanır. Bu bağa N-glikozit bağı denir. Baz böylece şekere tutunur."},{"t":"Fosfat bağı","a":"5' karbon","d":"Fosfat grubu, şekerin 5' karbonuna bağlanır. Bu fosfat nükleotidin bir ucunu oluşturur. Komşu nükleotitle bağlanmada görev alır."},{"t":"Serbest grup","a":"3' karbon","d":"Şekerin 3' karbonunda serbest bir hidroksil (-OH) grubu bulunur. Bu grup başka bir nükleotidin fosfatına bağlanabilir. Böylece zincir uzar."}],"ans":"Baz 1' karbona, fosfat 5' karbona bağlanır; 3' karbonda zincir uzamasını sağlayan hidroksil grubu bulunur."},{"q":"Nükleotitleri bir DNA ipliğinde birbirine bağlayan fosfodiester bağı tam olarak hangi gruplar arasında kurulur?","steps":[{"t":"Bağ noktaları","a":"3' OH ve 5' fosfat","d":"Fosfodiester bağı, bir nükleotidin şekerinin 3' hidroksil grubu ile komşu nükleotidin 5' fosfat grubu arasında kurulur. Bu iki grup birleşir. Bağ kovalent türdedir."},{"t":"Yön","a":"5'→3'","d":"Bu bağlanma şekli ipliğe bir yön kazandırır. Yeni nükleotitler 3' uca eklenir. Bu yüzden iplik 5'→3' yönünde büyür."},{"t":"Sonuç","a":"Omurga","d":"Tekrarlanan fosfodiester bağları şeker-fosfat omurgasını oluşturur. Omurga molekülün dış kısmındadır. Bazlar ise içe doğru uzanır."}],"ans":"Bir nükleotidin 3' hidroksil grubu ile komşunun 5' fosfat grubu arasında kurulur (3'-5' fosfodiester bağı)."},{"q":"DNA ve RNA nükleotitleri arasındaki şeker farkı (deoksiriboz/riboz) molekülün kararlılığını nasıl etkiler?","steps":[{"t":"Şeker farkı","a":"2' OH varlığı","d":"Ribozun 2' karbonunda bir hidroksil (-OH) grubu vardır. Deoksiribozda bu grup yoktur, yerine yalnızca hidrojen bulunur. Bu yüzden ismi \"deoksi\"dir."},{"t":"Kimyasal etki","a":"OH tepkimeye açık","d":"2' hidroksil grubu kimyasal tepkimelere açıktır. RNA omurgasının hidrolizini (parçalanmasını) kolaylaştırır. Bu da RNA'yı daha kararsız yapar."},{"t":"Sonuç","a":"DNA daha kararlı","d":"Deoksiribozda 2' OH bulunmadığından DNA omurgası daha az tepkimeye girer. Bu nedenle DNA daha kararlıdır. Uzun süreli bilgi deposu olmaya bu yüzden uygundur."}],"ans":"Ribozdaki 2' OH grubu hidrolizi kolaylaştırıp RNA'yı kararsız yapar; deoksiribozda bu grup olmadığından DNA daha kararlıdır."},{"q":"Bir nükleozit trifosfat (örneğin dATP) ile DNA ipliğindeki bir nükleotit arasındaki fark nedir?","steps":[{"t":"Nükleozit trifosfat","a":"Üç fosfat","d":"dATP gibi bir nükleozit trifosfat, şeker, baz ve üç fosfat grubu içerir. Hücrede serbest halde bulunur. Replikasyonda yapı taşı olarak kullanılır."},{"t":"Sentez","a":"İki fosfat kopar","d":"Yeni iplikte bir nükleotit eklenirken iki fosfat (pirofosfat) kopar. Bu kopma açığa enerji çıkarır. Bu enerji bağ kurulmasını sağlar."},{"t":"İplikteki hal","a":"Tek fosfat","d":"Sonuçta DNA ipliğinde her nükleotit yalnızca bir fosfat içerir. Yani iplik içindeki nükleotit monofosfat halindedir. Trifosfat hali sentez öncesi serbest formdur."}],"ans":"Nükleozit trifosfat üç fosfat içerir; sentez sırasında iki fosfat kopar ve iplikteki nükleotit tek fosfat (monofosfat) halinde kalır."},{"q":"Bir DNA nükleotidinde adenin bazı taşıyan birim ile guanin bazı taşıyan birim arasındaki tek fark nedir?","steps":[{"t":"Ortak parçalar","a":"Şeker ve fosfat aynı","d":"Her iki nükleotit de deoksiriboz şekeri ve fosfat grubu içerir. Bu iki parça tüm DNA nükleotitlerinde aynıdır. Dolayısıyla fark bu parçalardan kaynaklanmaz."},{"t":"Baz farkı","a":"Adenin ve guanin","d":"İki nükleotit yalnızca taşıdıkları organik bazda farklıdır. Biri adenin, diğeri guanin taşır. İkisi de pürin bazı olmasına rağmen yapıları birbirinden farklıdır."},{"t":"Sonuç","a":"Yalnızca baz","d":"Bu nedenle iki nükleotit arasındaki tek fark organik bazlarıdır. Şeker ve fosfat aynı kaldığı için bilgi farkını baz yaratır. Baz dizilimi genetik bilgiyi belirler."}],"ans":"Tek fark taşıdıkları organik bazdır; biri adenin diğeri guanin içerir, şeker ve fosfat aynıdır."},{"q":"DNA nükleotidinde N-glikozit bağı nedir ve hangi atomlar arasında kurulur?","steps":[{"t":"Bağın tanımı","a":"Baz-şeker bağı","d":"N-glikozit bağı, organik bazı şekere bağlayan kovalent bağdır. Nükleotidin baz ile şeker kısmını birleştirir. Her nükleotitte bu bağ bulunur."},{"t":"Bağ atomları","a":"Azot ve karbon","d":"Bu bağ, bazın bir azot atomu ile şekerin 1' karbonu arasında kurulur. Adı buradan gelir; \"N\" azotu temsil eder. Bağ baz ile şekeri sıkıca tutar."},{"t":"Önemi","a":"Yapı bütünlüğü","d":"N-glikozit bağı sayesinde baz şekerden ayrılmadan durur. Bu bağın kopması bazın kaybına yol açabilir. Böyle bir kayıp DNA hasarı sayılır."}],"ans":"Bazı şekere bağlayan kovalent bağdır; bazın azot atomu ile deoksiribozun 1' karbonu arasında kurulur."},{"q":"Bir DNA molekülünde 600 nükleotit varsa kaç tane fosfat grubu ve kaç tane deoksiriboz şekeri bulunur?","steps":[{"t":"Nükleotit yapısı","a":"Birer adet","d":"Her DNA nükleotidi bir fosfat, bir deoksiriboz ve bir baz içerir. Yani nükleotit başına bir şeker ve bir fosfat düşer. Bu kural tüm nükleotitler için geçerlidir."},{"t":"Fosfat sayısı","a":"600 fosfat","d":"Nükleotit sayısı kadar fosfat grubu vardır. 600 nükleotit varsa 600 fosfat grubu bulunur. Çünkü her nükleotitte bir fosfat vardır."},{"t":"Şeker sayısı","a":"600 şeker","d":"Aynı şekilde her nükleotitte bir deoksiriboz bulunur. 600 nükleotit için 600 deoksiriboz şekeri vardır. Şeker ve fosfat sayıları nükleotit sayısına eşittir."}],"ans":"600 fosfat grubu ve 600 deoksiriboz şekeri bulunur."},{"q":"Nükleotitlerin polimerleşmesi (DNA sentezi) sırasında neden enerji açığa çıkar?","steps":[{"t":"Yapı taşı","a":"Nükleozit trifosfat","d":"DNA sentezinde yapı taşı olarak nükleozit trifosfatlar kullanılır. Bunlar üç fosfat grubu taşır. Fosfatlar arasında yüksek enerjili bağlar vardır."},{"t":"Fosfat kopması","a":"Pirofosfat ayrılır","d":"Bir nükleotit zincire eklenirken iki fosfat pirofosfat halinde kopar. Yüksek enerjili bağlar kırılır. Bu kırılma enerji açığa çıkarır."},{"t":"Sürüklenme","a":"Tepkimeyi ileri iter","d":"Açığa çıkan enerji ve pirofosfatın sonradan parçalanması tepkimeyi ileri yönde sürükler. Böylece sentez kendiliğinden ve verimli olur. Bu, polimerleşmeyi kolaylaştırır."}],"ans":"Nükleozit trifosfatlardan iki fosfatın (pirofosfatın) yüksek enerjili bağları kırılınca enerji açığa çıkar ve sentezi ileri iter."},{"q":"DNA ve RNA nükleotitlerinin baz çeşitleri tam olarak hangileridir?","steps":[{"t":"DNA bazları","a":"A, T, G, C","d":"DNA nükleotitlerinde adenin, timin, guanin ve sitozin bazları bulunur. Pürinler adenin ve guanin, pirimidinler timin ve sitozindir. Toplam dört çeşit bazdır."},{"t":"RNA bazları","a":"A, U, G, C","d":"RNA nükleotitlerinde adenin, urasil, guanin ve sitozin bulunur. Timin yerine urasil yer alır. Geri kalan üç baz DNA ile ortaktır."},{"t":"Fark","a":"Timin / urasil","d":"İki molekül arasındaki baz farkı timin ve urasildir. DNA timin, RNA urasil içerir. Diğer üç baz (A, G, C) her ikisinde de bulunur."}],"ans":"DNA: A, T, G, C; RNA: A, U, G, C; fark timin (DNA) yerine urasil (RNA) bulunmasıdır."},{"q":"Bir DNA ipliğinin neden bir 5' ucu ve bir 3' ucu olur, bu yönlülük nükleotit yapısından nasıl kaynaklanır?","steps":[{"t":"Nükleotit yapısı","a":"Asimetrik şeker","d":"Her nükleotitte deoksiribozun 5' ve 3' karbonları farklı işlevler taşır. 5' karbonda fosfat, 3' karbonda hidroksil bulunur. Bu asimetri yön oluşturur."},{"t":"Bağlanma","a":"5' fosfat - 3' OH","d":"Nükleotitler birbirine 5' fosfat ile 3' hidroksil arasından bağlanır. Böylece zincirin bir ucunda serbest 5' fosfat, diğer ucunda serbest 3' hidroksil kalır. İplik yönlü hale gelir."},{"t":"İki uç","a":"5' ve 3' uçlar","d":"Serbest fosfat taşıyan uca 5' ucu, serbest hidroksil taşıyan uca 3' ucu denir. Bu yön, replikasyon ve transkripsiyon için belirleyicidir. Sentez daima 5'→3' yönünde ilerler."}],"ans":"Şekerin 5' (fosfat) ve 3' (hidroksil) karbonları farklı olduğundan zincirin bir ucu serbest 5' fosfat, diğeri serbest 3' hidroksil taşır; bu yönlülüğü yaratır."},{"q":"Nükleotitlerin yalnızca enerji depolama görevi de var mıdır, ATP buna nasıl bir örnektir?","steps":[{"t":"Nükleotit görevi","a":"Sadece DNA değil","d":"Nükleotitler yalnızca DNA ve RNA yapı taşı değildir. Hücrede başka görevler de üstlenirler. Bunlardan biri enerji aktarımıdır."},{"t":"ATP yapısı","a":"Adenin nükleotidi","d":"ATP (adenozin trifosfat) bir adenin nükleotididir; adenin, riboz ve üç fosfat içerir. Yani temelde bir nükleotittir. Fosfatları yüksek enerjili bağlarla bağlıdır."},{"t":"Enerji işlevi","a":"Hücre enerji birimi","d":"ATP'nin fosfat bağı kırıldığında enerji açığa çıkar. Bu enerji hücredeki birçok tepkimede kullanılır. Böylece nükleotitler enerji taşıma görevini de yerine getirir."}],"ans":"Evet; ATP, adenin-riboz-üç fosfattan oluşan bir nükleotittir ve fosfat bağlarındaki enerjiyle hücrenin enerji birimi olarak görev yapar."},{"q":"DNA nükleotidinde deoksiribozun karbon atomlarının numaralandırılmasında neden üs işareti (1', 2', 3'...) kullanılır?","steps":[{"t":"İki yapı","a":"Şeker ve baz","d":"Bir nükleotitte hem şeker hem de organik baz halka yapısı içerir. İki yapının da karbon ve azot atomları numaralandırılır. Bu atomları ayırt etmek gerekir."},{"t":"Karışıklık","a":"Aynı numaralar","d":"Hem bazın hem şekerin atomları 1, 2, 3 gibi sayılarla numaralanır. Bu durum karışıklığa yol açar. Hangi atomun nereye ait olduğu belirsizleşir."},{"t":"Çözüm","a":"Üs işareti","d":"Şekerin karbonları üs işaretiyle (1', 2', 3'...) yazılır. Böylece şekerin atomları bazınkilerden ayrılır. Örneğin 5' karbon şekere, 5 numara baza aittir."}],"ans":"Bazın atomları da numaralandığından karışıklığı önlemek için şekerin karbonları üs işaretiyle (1', 2'...) gösterilir."},{"q":"Bir nükleotitin \"monofosfat\", \"difosfat\" ve \"trifosfat\" formları arasındaki fark nedir, hücrede hangi formlar bulunur?","steps":[{"t":"Fosfat sayısı","a":"Bir, iki, üç","d":"Monofosfat bir, difosfat iki, trifosfat üç fosfat grubu içerir. Aralarındaki fark fosfat sayısıdır. Şeker ve baz aynı kalır."},{"t":"Enerji ilişkisi","a":"Fazla fosfat fazla enerji","d":"Fosfatlar arasındaki bağlar yüksek enerjilidir. Trifosfat formu en çok enerjiyi taşır. Fosfat koptukça enerji açığa çıkar."},{"t":"Hücredeki kullanım","a":"Sentezde trifosfat","d":"DNA ve RNA sentezinde yapı taşı olarak trifosfat formlar (örneğin dATP) kullanılır. İki fosfat kopunca nükleotit zincire monofosfat olarak katılır. Hücrede her üç form da farklı görevlerde bulunur."}],"ans":"Fark fosfat sayısıdır (bir, iki, üç); sentezde trifosfat kullanılır, zincire katılınca monofosfat olarak kalır."},{"q":"Nükleotitlerdeki organik bazların molekül içinde içe (sarmalın ortasına) yerleşmesi neden hidrofobik özellikleriyle ilişkilidir?","steps":[{"t":"Baz özelliği","a":"Hidrofobik","d":"Organik bazlar halkalı yapıları nedeniyle suyu sevmeyen (hidrofobik) özelliktedir. Suyla doğrudan temas etmekten kaçınırlar. Bu özellik yerleşimlerini etkiler."},{"t":"Omurga özelliği","a":"Hidrofilik","d":"Şeker-fosfat omurgası ise negatif yüklü ve suyu seven (hidrofilik) yapıdadır. Su ile rahatça etkileşir. Bu yüzden dışta yer alır."},{"t":"Yerleşim","a":"Bazlar içte","d":"Hidrofobik bazlar suyla teması azaltmak için sarmalın iç kısmına gizlenir. Hidrofilik omurga dışta su ile temas eder. Bu düzen çift sarmalın kararlılığını artırır."}],"ans":"Bazlar hidrofobik olduğundan suyla temastan kaçınmak için içe yerleşir; hidrofilik şeker-fosfat omurgası dışta kalır, bu da kararlılığı artırır."},{"q":"Genetik bilginin nükleotit dizisinde saklanması, bu dizinin proteine aktarılmasıyla nasıl ilişkilidir?","steps":[{"t":"Bilgi deposu","a":"Nükleotit dizisi","d":"DNA'daki nükleotitlerin (bazların) dizilme sırası genetik bilgiyi oluşturur. Bu dizi bir tür şifredir. Hücrenin yapacağı proteinleri belirler."},{"t":"Aktarım","a":"Transkripsiyon ve translasyon","d":"Önce DNA'daki dizi RNA'ya kopyalanır (transkripsiyon). Sonra RNA'daki nükleotit dizisi proteinin amino asit sırasına çevrilir (translasyon). Böylece bilgi proteine geçer."},{"t":"Kod ilişkisi","a":"Üçlü kod","d":"Nükleotitler üçerli gruplar (kodon) halinde okunur ve her üçlü bir amino asidi belirler. Yani nükleotit dizisi protein dizisini tayin eder. Böylece bilgi yapısal işleve dönüşür."}],"ans":"Nükleotit dizisindeki şifre, transkripsiyon ve translasyonla okunarak (üçlü kodonlar yoluyla) proteinin amino asit dizisini belirler."}],"zor":[{"q":"Bir DNA ipliği n adet nükleotitten oluşuyorsa, bu iplikte kaç tane fosfodiester bağı bulunur ve bunu genelleyiniz.","steps":[{"t":"Bağlanma mantığı","a":"Komşular arası","d":"Fosfodiester bağı yalnızca yan yana iki nükleotit arasında kurulur. Yani her bağ bir nükleotit çiftini bağlar. İlk nükleotidin öncesinde bağ yoktur."},{"t":"Sayma","a":"Aralıklar","d":"n nükleotit arka arkaya dizildiğinde aralarında (n−1) aralık oluşur. Her aralıkta bir fosfodiester bağı bulunur. Örneğin 5 nükleotit arasında 4 bağ vardır."},{"t":"Genelleme","a":"(n−1) bağ","d":"Bu nedenle n nükleotitlik bir iplik (n−1) fosfodiester bağı içerir. Çift sarmal için iki iplik olduğundan toplam 2(n−1) olur. Bu kural tüm doğrusal iplikler için geçerlidir."}],"ans":"n nükleotitlik iplikte (n−1) fosfodiester bağı bulunur; çift sarmalda toplam 2(n−1) bağ olur."},{"q":"Bir hücrede dTTP (timin nükleozit trifosfat) eksikliği oluşursa, DNA sentezi nasıl etkilenir ve neden?","steps":[{"t":"dTTP rolü","a":"Timin kaynağı","d":"dTTP, DNA'ya timin nükleotidi ekleyen yapı taşıdır. DNA sentezinde adenin karşısına timin yerleştirilir. Bu nükleotit olmadan timin eklenemez."},{"t":"Eşleşme gereği","a":"A karşısı boş kalır","d":"Kalıp iplikte adenin geldiğinde karşısına timin gerekir. dTTP yoksa polimeraz doğru nükleotidi ekleyemez. Sentez bu noktada duraklar."},{"t":"Sonuç","a":"Replikasyon durur","d":"Timin sağlanamadığı için yeni iplik tamamlanamaz ve replikasyon yavaşlar veya durur. Hücre bölünmesi engellenir. Bu ilke bazı kemoterapi ilaçlarının çalışma mantığını oluşturur."}],"ans":"dTTP olmadan adenin karşısına timin eklenemez; replikasyon o noktada duraklar ve DNA sentezi engellenir."},{"q":"Bir nükleotitteki organik baza göre nükleotitin pürin mi pirimidin mi olduğu, bir DNA molekülündeki toplam baz oranlarını nasıl belirler?","steps":[{"t":"Baz sınıfı","a":"Pürin / pirimidin","d":"Nükleotitler taşıdıkları baza göre pürin (A, G) veya pirimidin (T, C) nükleotidi olur. Pürinler çift halkalı, pirimidinler tek halkalıdır. Her nükleotit bu iki sınıftan birine girer."},{"t":"Eşleşme","a":"Pürin-pirimidin","d":"Çift sarmalda her pürin bir pirimidinle eşleşir (A-T, G-C). Bir iplikteki her pürin, karşı iplikte bir pirimidin yaratır. Bu eşleşme zorunludur."},{"t":"Toplam oran","a":"A+G = T+C","d":"Bu eşleşme nedeniyle tüm moleküldeki pürin sayısı pirimidin sayısına eşit olur (A+G = T+C). Dolayısıyla nükleotitin baz sınıfı, molekülün baz dengesini belirler. Bu, Chargaff kuralının temelidir."}],"ans":"Her pürin bir pirimidinle eşleştiğinden molekülde A+G = T+C olur; baz sınıfı bu dengeyi (Chargaff kuralını) belirler."},{"q":"Bir DNA çift sarmalında 1200 nükleotit vardır ve pürin nükleotitlerinin yüzde 30'u adenindir; molekülde kaç adenin, timin, guanin ve sitozin nükleotidi bulunur?","steps":[{"t":"Pürin-pirimidin","a":"Her biri 600","d":"Çift sarmalda pürin (A+G) sayısı pirimidin (T+C) sayısına eşittir. Toplam 1200 nükleotidin yarısı pürin, yarısı pirimidindir. Yani A+G = 600 ve T+C = 600'dür."},{"t":"Adenin sayısı","a":"A=180","d":"Pürinlerin %30'u adenindir: 600×0,30 = 180. Demek ki adenin sayısı 180'dir. Kalan pürin guanindir: 600 − 180 = 420, yani guanin 420'dir."},{"t":"Eşleşmeyle tamamlama","a":"T=180, C=420","d":"Chargaff kuralına göre timin adenine eşittir: T = A = 180. Sitozin guanine eşittir: C = G = 420. Böylece tüm baz sayıları belirlenir."}],"ans":"Adenin 180, timin 180, guanin 420 ve sitozin 420 nükleotit bulunur."},{"q":"DNA nükleotidindeki 3' hidroksil grubunun bulunması, replikasyonun yalnızca 5'→3' yönünde ilerlemesini nasıl açıklar?","steps":[{"t":"Polimeraz işlevi","a":"3' uca ekler","d":"DNA polimeraz enzimi yeni nükleotidi var olan zincirin serbest 3' ucuna ekler. Eklenecek nükleotidin fosfatı, zincirin 3' hidroksiline bağlanır. Bu yüzden serbest 3' OH zorunludur."},{"t":"Bağ kurulması","a":"3' OH + 5' fosfat","d":"Yeni gelen nükleotidin 5' fosfatı ile zincirin 3' hidroksili arasında fosfodiester bağı kurulur. Böylece zincir 3' ucundan uzar. Reaksiyon yalnızca bu yönde işleyebilir."},{"t":"Yön sonucu","a":"5'→3' büyüme","d":"Her ekleme 3' uca yapıldığından yeni iplik 5'→3' yönünde büyür. Polimeraz 3'→5' yönünde sentez yapamaz. Bu nedenle replikasyon kaçınılmaz olarak 5'→3' yönündedir."}],"ans":"Polimeraz yeni nükleotidi serbest 3' hidroksile bağladığından zincir hep 3' uçtan uzar; bu da sentezi yalnızca 5'→3' yönünde mümkün kılar."},{"q":"Bir nükleotitin baz, şeker ve fosfat oranları korunurken, RNA'nın DNA'ya göre daha kısa ömürlü olmasının nükleotit düzeyindeki nedeni nedir?","steps":[{"t":"Şeker farkı","a":"2' OH grubu","d":"RNA nükleotidindeki riboz şekeri 2' karbonunda hidroksil grubu taşır. DNA'daki deoksiriboz bu grubu içermez. Tek yapısal fark budur."},{"t":"Kimyasal tepkime","a":"Kendi kendine kesilme","d":"2' hidroksil grubu komşu fosfodiester bağına saldırarak omurgayı kesebilir. Bu, RNA'nın kendiliğinden parçalanmasını kolaylaştırır. Özellikle bazik ortamda hızlanır."},{"t":"Ömür farkı","a":"RNA daha kararsız","d":"Deoksiribozda 2' OH olmadığından DNA bu tür kesilmeye uğramaz ve uzun ömürlüdür. RNA ise daha kolay parçalandığı için kısa ömürlüdür. Bu da hücrenin RNA'yı geçici aracı, DNA'yı kalıcı depo olarak kullanmasını sağlar."}],"ans":"RNA'daki ribozun 2' hidroksil grubu omurgayı kendiliğinden kesebildiğinden RNA kararsız ve kısa ömürlüdür; DNA'da bu grup yoktur."},{"q":"Bir DNA molekülünün bir ipliğinde 5'-ATGCGTACG-3' dizisi varsa, bu ipliği oluşturan nükleotitlerden kaç tanesi pürin, kaç tanesi pirimidin nükleotididir, ve karşı iplikte bu sayılar nasıl değişir?","steps":[{"t":"Verilen iplik","a":"Pürin: A, G","d":"Verilen iplik 5'-ATGCGTACG-3'tür. Pürinler A ve G'dir. Dizide A: 2 (1. ve 8. baz), G: 3 (3., 5., 9. baz) bulunur; toplam 5 pürin."},{"t":"Pirimidin sayımı","a":"Pirimidin: T, C","d":"Pirimidinler T ve C'dir. Dizide T: 2 (2. ve 6. baz), C: 2 (4. ve 7. baz) vardır; toplam 4 pirimidin. Böylece iplikte 5 pürin, 4 pirimidin bulunur."},{"t":"Karşı iplik","a":"Ters döner: 4 pürin, 5 pirimidin","d":"Karşı iplikte her baz tamamlayıcısına döner: pürinler pirimidine, pirimidinler pürine dönüşür. Verilen iplikte 5 pürin vardı, karşıda bunlar 5 pirimidin olur; 4 pirimidin de 4 pürin olur. Yani karşı iplikte 4 pürin, 5 pirimidin nükleotit bulunur."}],"ans":"Verilen iplikte 5 pürin, 4 pirimidin; karşı iplikte ise tersine 4 pürin, 5 pirimidin nükleotit bulunur."},{"q":"Hücrede nükleotitlerin sadece A, T, G, C bazlarıyla sınırlı kalması (ek baz türlerinin standart olmaması) DNA'nın işlevi açısından neden avantajlıdır?","steps":[{"t":"Standart eşleşme","a":"Sabit kurallar","d":"Yalnızca dört baz olması A-T ve G-C gibi sabit eşleşme kurallarını mümkün kılar. Her bazın tek bir tamamlayıcısı vardır. Bu, eşleşmeyi belirsizlikten kurtarır."},{"t":"Kopyalama doğruluğu","a":"Az hata","d":"Sabit eşleşme kuralları replikasyonun yüksek doğrulukla yapılmasını sağlar. Polimeraz hangi nükleotidi ekleyeceğini kesin bilir. Az sayıda baz, hata olasılığını azaltır."},{"t":"Tamir kolaylığı","a":"Hata tanıma","d":"Dört baza dayalı sistem, tamir enzimlerinin yanlış eşleşmeleri kolayca tanımasını sağlar. Standart dışı bir baz hemen hata olarak algılanır. Böylece genetik bilgi kararlılıkla korunur."}],"ans":"Dört baza dayalı sabit eşleşme, replikasyonun doğruluğunu ve tamir enzimlerinin hatayı tanımasını kolaylaştırarak bilgiyi güvenle korur."},{"q":"Bir DNA ipliğinde nükleotitler arasındaki fosfodiester bağı bir enzimle kesilirse molekülün hangi kısmı bozulur ve hidrojen bağlarıyla farkı nedir?","steps":[{"t":"Fosfodiester konumu","a":"Omurgada","d":"Fosfodiester bağı bir iplik boyunca şeker ve fosfat arasında kurulur. Bu bağlar şeker-fosfat omurgasını oluşturur. Yani fosfodiester bağı omurganın yapısal bağıdır."},{"t":"Kesilme etkisi","a":"İplik kırılır","d":"Bu bağ kesilirse omurga kopar ve iplik iki parçaya ayrılır. Nükleotit zinciri bölünür. Bu, DNA'nın yapısal bütünlüğünü bozan ciddi bir hasardır."},{"t":"Hidrojen bağı farkı","a":"İplikleri ayırır, kırmaz","d":"Hidrojen bağları ise iki iplik arasında bazları tutar; kırılınca iplikler ayrılır ama her iplik bütün kalır. Fosfodiester bağı kovalent ve güçlüyken hidrojen bağı zayıftır. Biri omurgayı, diğeri iki iplik arası eşleşmeyi sağlar."}],"ans":"Fosfodiester bağı kesilince şeker-fosfat omurgası kırılıp iplik kopar; hidrojen bağları ise yalnızca iki ipliği ayırır, iplikleri kırmaz."},{"q":"Bir virüsün genetik materyali tek iplikli RNA olduğunda, nükleotit yapısı bakımından çift iplikli DNA'dan hangi açılardan farklılaşır?","steps":[{"t":"Şeker farkı","a":"Riboz","d":"RNA nükleotitleri riboz şekeri içerir, DNA ise deoksiriboz. Ribozda fazladan bir 2' hidroksil grubu vardır. Bu, RNA'yı kimyasal olarak daha tepkin yapar."},{"t":"Baz farkı","a":"Urasil","d":"RNA'da timin yerine urasil bulunur. Adenin, urasille eşleşir. Diğer bazlar (A, G, C) DNA ile ortaktır."},{"t":"İplik sayısı","a":"Tek iplik","d":"Tek iplikli RNA'da karşı bir tamamlayıcı iplik bulunmaz. Bu yüzden Chargaff kuralları (A=U, G=C) zorunlu olarak geçerli değildir. Tek iplik olması bilgiyi yedeklemediğinden RNA daha kararsız ve mutasyona açıktır."}],"ans":"RNA nükleotidi riboz ve urasil içerir, tek iplikli olduğundan tamamlayıcı yedeği ve zorunlu Chargaff dengesi yoktur; bu da onu daha kararsız ve değişken kılar."},{"q":"Nükleotitlerin polimerleşmesinde dehidrasyon (su çıkışı) tepkimesinin rolü nedir ve bu, omurganın oluşumuyla nasıl ilişkilidir?","steps":[{"t":"Bağ kurulması","a":"Su açığa çıkar","d":"İki nükleotit birleşirken bir su molekülü açığa çıkar. Bu tür tepkimeye dehidrasyon (kondansasyon) denir. Bir nükleotidin grubu ile diğerininki birleşirken su ayrılır."},{"t":"Fosfodiester bağı","a":"Kovalent bağ","d":"Su çıkışıyla birlikte 3' hidroksil ile 5' fosfat arasında fosfodiester bağı oluşur. Bu kovalent bağ nükleotitleri kalıcı olarak birbirine tutar. Her yeni bağda yine su açığa çıkar."},{"t":"Omurga oluşumu","a":"Tekrarlı bağlar","d":"Bu dehidrasyon tepkimeleri tekrarlandıkça şeker-fosfat omurgası uzar. Her nükleotit eklenişinde bir su ayrılır. Böylece uzun nükleotit zinciri (DNA omurgası) oluşur."}],"ans":"Her nükleotit eklenişinde su çıkışıyla 3' OH ve 5' fosfat arasında fosfodiester bağı kurulur; bu tekrarlı dehidrasyon tepkimeleri şeker-fosfat omurgasını oluşturur."},{"q":"Bir DNA molekülünde guanin nükleotidi oranı yüzde 22 ise, adenin nükleotidi oranı yüzde kaçtır ve bu hesabı nükleotit eşleşmesiyle açıklayınız.","steps":[{"t":"G ve C","a":"C=G=%22","d":"Çift sarmalda guanin nükleotidi sitozin nükleotidiyle eşleşir, bu yüzden oranları eşittir. Guanin %22 ise sitozin de %22'dir. G+C toplamı %44 olur."},{"t":"Kalan oran","a":"A+T=%56","d":"Tüm nükleotitlerin toplamı %100'dür. G+C %44 olduğundan A+T = %100 − %44 = %56'dır. Bu kısım adenin ve timin nükleotitlerine aittir."},{"t":"A hesabı","a":"A=%28","d":"Adenin nükleotidi timin nükleotidiyle eşleşir, oranları eşittir (A=T). A+T %56 olduğundan her biri %28 olur. Dolayısıyla adenin nükleotidi oranı %28'dir."}],"ans":"Adenin nükleotidi oranı yüzde 28'dir (G=C=%22, A+T=%56, A=T=%28)."},{"q":"Bazı kanser ilaçları nükleotit benzeri moleküller (analoglar) içerir; bu analogların DNA sentezini durdurma mekanizmasını nükleotit yapısı üzerinden açıklayınız.","steps":[{"t":"Analog yapısı","a":"Eksik 3' OH","d":"Nükleotit analogları gerçek nükleotitlere benzer ama genellikle 3' hidroksil grubu eksiktir. Polimeraz onları gerçek nükleotit sanarak zincire ekler. Yapısal benzerlik bunu mümkün kılar."},{"t":"Zincir uzaması","a":"Bir sonraki bağ kurulamaz","d":"Analog zincire katılınca, eksik 3' hidroksil nedeniyle bir sonraki nükleotidin fosfatı bağlanamaz. Yani fosfodiester bağı kurulamaz. Zincir uzaması durur."},{"t":"Sonuç","a":"Replikasyon engellenir","d":"Zincir tamamlanamadığı için DNA sentezi durur ve hücre bölünemez. Hızlı bölünen kanser hücreleri bundan daha çok etkilenir. Bu nedenle bu analoglar kanser tedavisinde kullanılır."}],"ans":"Analoglar genellikle 3' hidroksilden yoksundur; zincire eklendiklerinde sonraki nükleotit bağlanamaz, böylece DNA sentezi durur ve hücre bölünmesi engellenir."},{"q":"Nükleotitlerin baz, şeker ve fosfat bileşenlerinin kimyasal özellikleri (asidik/bazik) DNA'nın neden \"nükleik asit\" olarak adlandırıldığını nasıl açıklar?","steps":[{"t":"Fosfat grubu","a":"Asidik","d":"Nükleotitteki fosfat grupları asidik özellik gösterir ve negatif yük taşır. Çok sayıda fosfat omurgaya genel olarak asidik karakter kazandırır. Bu, molekülün yükünü belirler."},{"t":"Konum","a":"Çekirdekte yoğun","d":"Bu moleküller ilk kez hücre çekirdeğinde (nukleus) yoğun olarak bulunmuştur. \"Nükleik\" sözcüğü çekirdek anlamındaki nukleustan gelir. Yani adın bir kısmı konumu yansıtır."},{"t":"Ad","a":"Nükleik asit","d":"Çekirdekte bulunması \"nükleik\", fosfatların asidik olması \"asit\" adını verir. Birleşince \"nükleik asit\" terimi ortaya çıkar. DNA da deoksiribonükleik asittir; içindeki deoksiriboz şekerini belirtir."}],"ans":"Fosfat grupları molekülü asidik yapar, çekirdekte bulunması \"nükleik\" adını verir; birleşince \"nükleik asit\" (DNA: deoksiribonükleik asit) olur."},{"q":"Bir nükleotidin baz kısmı zarar görüp koparsa (apürinik/apirimidinik bölge oluşursa) DNA replikasyonu ve onarımı nükleotit düzeyinde nasıl etkilenir?","steps":[{"t":"Baz kaybı","a":"Boş şeker-fosfat","d":"N-glikozit bağının kopmasıyla baz kaybolur, ancak şeker-fosfat omurgası yerinde kalır. Bu bölgeye apürinik (pürin kaybı) veya apirimidinik bölge denir. Burada eşleşecek bir baz yoktur."},{"t":"Replikasyon sorunu","a":"Şablon bilgisi yok","d":"Replikasyon sırasında bu bölgede polimeraz hangi nükleotidi ekleyeceğini bilemez. Çünkü karşıya yazılacak baz bilgisi kayıptır. Bu, yanlış baz eklenmesine veya duraklamaya yol açabilir."},{"t":"Onarım","a":"Karşı iplik kalıp","d":"Onarım enzimleri hasarlı bölgeyi keser ve sağlam karşı ipliği kalıp alarak doğru nükleotidi yeniden yerleştirir. Tamamlayıcılık kuralı doğru bazın seçilmesini sağlar. Böylece kayıp baz orijinaline uygun biçimde tamamlanır."}],"ans":"Baz kopunca omurga kalır ama şablon bilgisi kaybolur; replikasyonda hata riski doğar, onarımda ise karşı iplik kalıp alınarak doğru nükleotit yeniden yerleştirilir."}]}},"bazEslesme":{"ilkokul":{"kolay":[{"q":"DNA merdiveninde adenin (A) bazının karşısına hangi baz gelir?","steps":[{"t":"Eşleşme kuralını hatırla","a":"A her zaman T ile eşleşir","d":"DNA iki ipliğin birbirine bağlanmasıyla oluşur. Bu ipliklerdeki bazlar rastgele değil, belirli bir kurala göre karşı karşıya gelir."},{"t":"A bazının çiftini bul","a":"Adeninin çifti timindir","d":"Adenin (A) bazının karşısına her zaman timin (T) bazı gelir. Bu yüzden bir iplikte A varsa, karşısındaki iplikte aynı yerde T bulunur."}],"ans":"Adeninin (A) karşısına timin (T) gelir."},{"q":"DNA merdiveninde guanin (G) bazının karşısına hangi baz gelir?","steps":[{"t":"Eşleşme kuralını hatırla","a":"G her zaman C ile eşleşir","d":"DNA bazları belirli çiftler halinde karşı karşıya gelir. Bazlar gelişigüzel değil, sabit bir kurala göre eşleşir."},{"t":"G bazının çiftini bul","a":"Guaninin çifti sitozindir","d":"Guanin (G) bazının karşısına her zaman sitozin (C) bazı gelir. Bir iplikte G varsa, karşısındaki yerde C bulunur."}],"ans":"Guaninin (G) karşısına sitozin (C) gelir."},{"q":"DNA bazları kaç tanesi birbiriyle eşleşerek çiftler oluşturur?","steps":[{"t":"Baz çiftlerini düşün","a":"Bazlar ikişerli çiftler oluşturur","d":"DNA merdiveninin her basamağında iki baz karşı karşıya durur. Bu iki baz birlikte bir baz çifti oluşturur."},{"t":"Eşleşmeleri say","a":"A-T ve G-C olmak üzere iki çift vardır","d":"Adenin timinle, guanin de sitozinle eşleşir. Yani toplamda iki farklı baz çifti bulunur: A-T ve G-C."}],"ans":"Bazlar ikişerli eşleşir: A-T ve G-C çiftleri oluşur."},{"q":"Bir DNA ipliğinde sırasıyla A-T-G bazları varsa, karşı iplikte hangi bazlar bulunur?","steps":[{"t":"Her bazın çiftini yaz","a":"A için T, T için A, G için C","d":"Her bazın karşısına eşleştiği baz gelir. A timinle, T adeninle, G ise sitozinle eşleşir."},{"t":"Karşı ipliği oluştur","a":"Karşı iplik T-A-C olur","d":"A-T-G dizisinin karşısına sırayla T-A-C bazları gelir. Böylece iki iplik birbirini tamamlar."}],"ans":"Karşı iplikte T-A-C bazları bulunur."},{"q":"DNA merdiveninin basamaklarını oluşturan yapılar nelerdir?","steps":[{"t":"Merdivenin yapısını düşün","a":"Basamakları bazlar oluşturur","d":"DNA bir merdivene benzetilir. Merdivenin basamaklarını karşı karşıya gelen bazlar meydana getirir."},{"t":"Hangi bazların eşleştiğini söyle","a":"A-T ve G-C basamakları yapar","d":"Her basamak iki bazın eşleşmesiyle oluşur. Adenin timinle, guanin sitozinle birleşerek basamakları yapar."}],"ans":"Basamakları eşleşen bazlar (A-T ve G-C) oluşturur."}],"zor":[{"q":"Bir DNA ipliğinde A-A-G-C-T bazları varsa, karşı ipliğin baz dizisi nasıl olur?","steps":[{"t":"Eşleşme kuralını hatırla","a":"A-T ve G-C eşleşir","d":"Her bazın belirli bir çifti vardır. Adenin timinle, guanin sitozinle, timin adeninle ve sitozin guaninle eşleşir."},{"t":"Her bazı tek tek eşle","a":"A→T, A→T, G→C, C→G, T→A","d":"Verilen dizideki her bazın karşısına çifti yazılır. A için T, G için C, C için G ve T için A gelir."},{"t":"Karşı ipliği yaz","a":"Sonuç T-T-C-G-A","d":"Bütün eşleşmeler sırayla yazıldığında karşı iplik T-T-C-G-A olur. İki iplik birbirini tamamlar."}],"ans":"Karşı iplik T-T-C-G-A olur."},{"q":"Bir DNA örneğinde 10 tane adenin (A) varsa, kaç tane timin (T) bulunur?","steps":[{"t":"Eşleşme kuralını düşün","a":"A daima T ile eşleşir","d":"DNA da adenin her zaman timinle karşı karşıya gelir. Bu yüzden her adeninin bir timin çifti vardır."},{"t":"Sayıyı hesapla","a":"A sayısı kadar T olur","d":"Adenin ve timin her zaman eşit sayıda bulunur. 10 adenin varsa karşılarında 10 timin olmalıdır."}],"ans":"10 tane timin (T) bulunur."},{"q":"Bir DNA da guanin (G) ve sitozin (C) sayıları neden birbirine eşittir?","steps":[{"t":"Eşleşmeyi hatırla","a":"G her zaman C ile eşleşir","d":"DNA da guanin yalnızca sitozinle eşleşir. Bir iplikteki her guaninin karşısında bir sitozin bulunur."},{"t":"Eşitliği açıkla","a":"Her G için bir C olduğundan sayıları eşittir","d":"Her guanin bir sitozinle çift oluşturduğu için sayıları daima aynı olur. Bu yüzden DNA da G sayısı C sayısına eşittir."}],"ans":"Her guanin bir sitozinle eşleştiği için G ve C sayıları eşittir."},{"q":"Bir DNA ipliğinde T-C-A-G-G bazları varsa, karşı iplikteki bazları bul.","steps":[{"t":"Eşleşme çiftlerini yaz","a":"T-A, C-G, A-T, G-C","d":"Her bazın çifti bellidir. Timin adeninle, sitozin guaninle, adenin timinle ve guanin sitozinle eşleşir."},{"t":"Diziyi eşle","a":"T→A, C→G, A→T, G→C, G→C","d":"Verilen dizideki her bazın karşısına çifti yazılır. Sırayla A, G, T, C ve C bazları elde edilir."},{"t":"Karşı ipliği yaz","a":"Sonuç A-G-T-C-C","d":"Tüm eşleşmeler birleştirildiğinde karşı iplik A-G-T-C-C olur. Böylece iki iplik tamamlayıcı şekilde durur."}],"ans":"Karşı iplik A-G-T-C-C olur."},{"q":"Bir DNA parçasında 4 tane G-C çifti ve 3 tane A-T çifti varsa toplam kaç baz çifti vardır?","steps":[{"t":"Çiftleri ayrı ayrı say","a":"4 tane G-C, 3 tane A-T","d":"DNA da bazlar çiftler halinde durur. Burada 4 tane guanin-sitozin çifti ve 3 tane adenin-timin çifti verilmiştir."},{"t":"Toplamı bul","a":"4 + 3 = 7 çift","d":"Tüm çiftleri toplamak gerekir. 4 G-C çifti ile 3 A-T çifti toplanınca 7 baz çifti elde edilir."}],"ans":"Toplam 7 baz çifti vardır."}]},"ortaokul":{"kolay":[{"q":"DNA da adenin ile timin arasında kaç tane hidrojen bağı bulunur?","steps":[{"t":"Bağ kuralını hatırla","a":"A-T arasında bağ sayısı azdır","d":"DNA da karşı karşıya gelen bazlar hidrojen bağları ile birbirine tutunur. Bu bağların sayısı baz çiftine göre değişir."},{"t":"A-T bağ sayısını söyle","a":"A ile T arasında 2 hidrojen bağı vardır","d":"Adenin ve timin arasında 2 hidrojen bağı kurulur. Bunu A=T şeklinde gösterebiliriz."}],"ans":"A ile T arasında 2 hidrojen bağı bulunur (A=T)."},{"q":"DNA da guanin ile sitozin arasında kaç tane hidrojen bağı bulunur?","steps":[{"t":"Bağ kuralını hatırla","a":"G-C arasında daha çok bağ vardır","d":"Bazlar hidrojen bağları ile tutunur ve bağ sayısı çiftine göre değişir. Guanin-sitozin çiftinin bağ sayısı adenin-timinden farklıdır."},{"t":"G-C bağ sayısını söyle","a":"G ile C arasında 3 hidrojen bağı vardır","d":"Guanin ve sitozin arasında 3 hidrojen bağı kurulur. Bunu G≡C şeklinde gösterebiliriz."}],"ans":"G ile C arasında 3 hidrojen bağı bulunur (G≡C)."},{"q":"DNA ipliklerini birbirine bağlayan bağ türü nedir?","steps":[{"t":"Bazların nasıl tutunduğunu düşün","a":"Karşı bazlar arasında bağ kurulur","d":"DNA nın iki ipliği karşı karşıya gelen bazlar sayesinde bir arada durur. Bu bazlar arasında özel bir bağ türü bulunur."},{"t":"Bağ türünü söyle","a":"Bu bağlar hidrojen bağıdır","d":"Karşılıklı bazlar arasında hidrojen bağları kurulur. Bu bağlar zayıftır, böylece iplikler gerektiğinde kolayca ayrılabilir."}],"ans":"İplikleri bazlar arasındaki hidrojen bağları birbirine bağlar."},{"q":"Adenin ve guanin pürin, timin ve sitozin pirimidin grubundadır. Bir baz çiftinde her zaman kaç pürin bulunur?","steps":[{"t":"Eşleşmeyi incele","a":"Pürin daima pirimidinle eşleşir","d":"DNA da büyük bir baz (pürin) ile küçük bir baz (pirimidin) eşleşir. A-T ve G-C çiftlerinin her ikisinde de bir pürin ve bir pirimidin vardır."},{"t":"Sayıyı belirle","a":"Her çiftte 1 pürin bulunur","d":"Adenin-timin çiftinde adenin pürindir, guanin-sitozin çiftinde guanin pürindir. Bu yüzden her baz çiftinde tam olarak 1 pürin yer alır."}],"ans":"Her baz çiftinde 1 pürin (ve 1 pirimidin) bulunur."},{"q":"Chargaff kuralına göre bir DNA da adenin sayısı %30 ise timin yüzdesi kaçtır?","steps":[{"t":"Chargaff kuralını hatırla","a":"A ile T sayıları eşittir","d":"Chargaff kuralına göre DNA da adenin miktarı timine eşittir. Çünkü her adenin bir timinle eşleşir."},{"t":"Yüzdeyi bul","a":"A %30 ise T de %30 olur","d":"Adenin ve timin eşit olduğundan yüzdeleri de aynıdır. Adenin %30 ise timin de %30 olmalıdır."}],"ans":"Timin yüzdesi %30 dur."}],"zor":[{"q":"Bir DNA da G≡C çiftleri, A=T çiftlerinden daha güçlü tutunur. Bunun nedenini hidrojen bağlarıyla açıkla.","steps":[{"t":"Bağ sayılarını yaz","a":"A=T 2 bağ, G≡C 3 bağ","d":"Adenin ile timin arasında 2 hidrojen bağı, guanin ile sitozin arasında 3 hidrojen bağı vardır. Bağ sayıları farklıdır."},{"t":"Bağ sayısı ile güç ilişkisini kur","a":"Daha çok bağ daha güçlü tutar","d":"Hidrojen bağı sayısı arttıkça bazlar birbirine daha sıkı tutunur. 3 bağ, 2 bağdan daha güçlü bir bağlanma sağlar."},{"t":"Sonucu açıkla","a":"G≡C daha sıkı tutunur","d":"Guanin-sitozin çifti 3 bağla bağlandığı için adenin-timin çiftinden daha güçlüdür. Bu yüzden G-C bakımından zengin DNA bölgeleri daha zor ayrılır."}],"ans":"G≡C 3, A=T 2 hidrojen bağı taşır; daha çok bağ daha güçlü tutunma sağlar."},{"q":"Bir DNA ipliğinde 5'-A-G-C-T-A-3' dizisi varsa, tamamlayıcı ipliğin dizisini bul.","steps":[{"t":"Eşleşme kurallarını yaz","a":"A-T, G-C, C-G, T-A","d":"Her baz kendi çiftiyle eşleşir. Adenin timinle, guanin sitozinle, sitozin guaninle ve timin adeninle karşılıklı durur."},{"t":"Her bazı eşle","a":"A→T, G→C, C→G, T→A, A→T","d":"Verilen dizideki bazlar tek tek eşlenir. Sırayla T, C, G, A ve T bazları elde edilir."},{"t":"Tamamlayıcı diziyi yaz","a":"Tamamlayıcı iplik T-C-G-A-T","d":"Eşleşen bazlar birleştirildiğinde tamamlayıcı iplik 3'-T-C-G-A-T-5' olur. İki iplik ters yönlü ve birbirini tamamlar."}],"ans":"Tamamlayıcı iplik T-C-G-A-T olur."},{"q":"Bir DNA molekülünde adenin %20 ise, guanin yüzdesi kaçtır? (Chargaff kuralı)","steps":[{"t":"A-T eşitliğini kullan","a":"A %20 ise T %20","d":"Chargaff kuralına göre adenin timine eşittir. Adenin %20 olduğundan timin de %20 olur."},{"t":"A ve T toplamını bul","a":"A + T = %40","d":"Adenin ve timin yüzdeleri toplanır. %20 adenin ile %20 timin toplamda %40 eder."},{"t":"G ve C payını paylaştır","a":"G + C = %60, G = %30","d":"Tüm bazlar %100 yaptığına göre G+C %60 kalır. Guanin sitozine eşit olduğundan ikisi %60 ı paylaşır ve guanin %30 olur."}],"ans":"Guanin yüzdesi %30 dur."},{"q":"Pürin daima pirimidinle eşleşir. Eğer iki pürin karşı karşıya gelseydi DNA merdiveninde ne sorun çıkardı?","steps":[{"t":"Baz boyutlarını karşılaştır","a":"Pürinler büyük, pirimidinler küçüktür","d":"Adenin ve guanin (pürinler) çift halkalı ve büyük yapılıdır. Timin ve sitozin (pirimidinler) tek halkalı ve küçüktür."},{"t":"İki pürin durumunu düşün","a":"İki büyük baz çok yer kaplar","d":"Karşı karşıya iki pürin gelseydi toplam genişlik çok fazla olurdu. Bu, merdiven basamağının olması gereken aralığa sığmazdı."},{"t":"Sonucu açıkla","a":"DNA genişliği bozulur","d":"Pürin-pürin eşleşmesi merdiveni bir yerde şişirir, pirimidin-pirimidin eşleşmesi ise daraltırdı. Pürin-pirimidin eşleşmesi sayesinde DNA her yerde aynı genişlikte kalır."}],"ans":"İki pürin çok geniş olur; DNA nın eşit genişliği bozulurdu."},{"q":"Bir DNA ipliğinde 30 adenin, 20 guanin bulunuyor. Bu çift iplikli DNA da toplam kaç baz vardır?","steps":[{"t":"Eşleşmeleri kullan","a":"A=T ve G=C","d":"Bir iplikteki her adenin karşı iplikte bir timinle, her guanin bir sitozinle eşleşir. Çift iplikte adenin sayısı timine, guanin sayısı sitozine eşittir."},{"t":"Her bazın toplamını bul","a":"T=30, C=20","d":"Adenin 30 ise timin de 30 olur. Guanin 20 ise sitozin de 20 olur."},{"t":"Tüm bazları topla","a":"30+30+20+20 = 100","d":"Bütün baz sayıları toplanır: 30 A, 30 T, 20 G ve 20 C. Bunların toplamı 100 baz eder."}],"ans":"Çift iplikli DNA da toplam 100 baz bulunur."}]},"lise":{"kolay":[{"q":"DNA da baz eşleşmesinin tamamlayıcı (komplementer) olması ne anlama gelir?","steps":[{"t":"Tamamlayıcılık kavramını tanımla","a":"Her bazın belirli bir çifti vardır","d":"Tamamlayıcılık, bir iplikteki baz dizisinin karşı iplikteki diziyi tam olarak belirlemesidir. A daima T ile, G daima C ile eşleşir."},{"t":"Sonucu ifade et","a":"Bir iplik diğerini belirler","d":"Bir iplikteki dizi bilinirse, kurallar sayesinde karşı iplik kesin olarak yazılabilir. Bu yüzden iki iplik birbirinin tamamlayıcısıdır."}],"ans":"Bir iplikteki her bazın çifti bellidir; iplikler birbirini tam tamamlar."},{"q":"A=T ve G≡C gösterimlerindeki çizgi sayıları neyi ifade eder?","steps":[{"t":"Gösterimi incele","a":"Çizgiler bağları temsil eder","d":"A=T ve G≡C gösterimlerinde bazlar arasındaki çizgiler hidrojen bağlarını gösterir. Çizgi sayısı bağ sayısına eşittir."},{"t":"Sayıları belirt","a":"A=T 2 bağ, G≡C 3 bağ","d":"A=T çiftinde iki çizgi iki hidrojen bağını, G≡C çiftinde üç çizgi üç hidrojen bağını ifade eder. Bu yüzden gösterimdeki çizgi sayısı önemlidir."}],"ans":"Çizgiler hidrojen bağı sayısını gösterir: A=T 2, G≡C 3."},{"q":"Pürin ve pirimidin bazlarını gruplandırarak yazınız.","steps":[{"t":"Pürinleri belirle","a":"Adenin ve guanin pürindir","d":"Pürinler çift halkalı bazlardır. DNA daki pürin bazları adenin (A) ve guanindir (G)."},{"t":"Pirimidinleri belirle","a":"Timin ve sitozin pirimidindir","d":"Pirimidinler tek halkalı bazlardır. DNA daki pirimidin bazları timin (T) ve sitozindir (C)."}],"ans":"Pürinler: adenin ve guanin; pirimidinler: timin ve sitozin."},{"q":"Chargaff kuralına göre çift iplikli DNA da hangi eşitlikler geçerlidir?","steps":[{"t":"A-T eşitliğini yaz","a":"A miktarı T ye eşittir","d":"Chargaff kuralının birincisine göre adenin miktarı timine eşittir. Çünkü her adenin bir timinle eşleşir."},{"t":"G-C eşitliğini yaz","a":"G miktarı C ye eşittir","d":"Kuralın ikinci bölümüne göre guanin miktarı sitozine eşittir. Her guanin bir sitozinle eşleştiği için bu eşitlik geçerlidir."}],"ans":"Chargaff kuralı: A=T ve G=C dir."},{"q":"Bir DNA ipliğinde 5'-T-A-C-G-3' dizisi varsa tamamlayıcı iplik nasıl olur?","steps":[{"t":"Eşleşme kurallarını uygula","a":"T-A, A-T, C-G, G-C","d":"Her bazın çifti yazılır. Timin adeninle, adenin timinle, sitozin guaninle ve guanin sitozinle eşleşir."},{"t":"Tamamlayıcı diziyi oluştur","a":"Sonuç A-T-G-C","d":"Eşleşmeler sırayla birleştirildiğinde tamamlayıcı iplik 3'-A-T-G-C-5' olur. İki iplik ters yönlüdür."}],"ans":"Tamamlayıcı iplik A-T-G-C olur."},{"q":"DNA daki hidrojen bağlarının zayıf olması canlı için neden bir avantajdır?","steps":[{"t":"Bağ özelliğini düşün","a":"Hidrojen bağları zayıf bağlardır","d":"Bazlar arasındaki hidrojen bağları kovalent bağlara göre zayıftır. Bu sayede iplikler kolayca açılıp kapanabilir."},{"t":"Avantajı açıkla","a":"İplikler kolay ayrılır","d":"Replikasyon ve protein sentezi için DNA ipliklerinin geçici olarak ayrılması gerekir. Zayıf bağlar bu ayrılmayı kolaylaştırır ve enerji tasarrufu sağlar."}],"ans":"Zayıf bağlar iplikleri gerektiğinde kolayca açıp ayırmayı sağlar."},{"q":"Bir DNA da sitozin oranı %25 ise guanin oranı kaçtır?","steps":[{"t":"G-C eşitliğini hatırla","a":"G miktarı C ye eşittir","d":"Chargaff kuralına göre çift iplikli DNA da guanin sitozine eşittir. Her guanin bir sitozinle eşleştiği için oranları aynıdır."},{"t":"Oranı yaz","a":"C %25 ise G de %25","d":"Guanin ve sitozin eşit olduğundan yüzdeleri de eşittir. Sitozin %25 ise guanin de %25 olmalıdır."}],"ans":"Guanin oranı %25 tir."},{"q":"DNA da bir baz çiftinin her zaman bir pürin ve bir pirimidinden oluşması neyi sağlar?","steps":[{"t":"Pürin-pirimidin eşleşmesini hatırla","a":"Büyük baz küçük bazla eşleşir","d":"Her çiftte bir pürin (büyük) ve bir pirimidin (küçük) bulunur. A-T ve G-C çiftlerinin ikisinde de bu durum geçerlidir."},{"t":"Sağladığını açıkla","a":"DNA genişliği sabit kalır","d":"Bir büyük ile bir küçük baz birleşince her basamağın toplam genişliği aynı olur. Bu yüzden DNA molekülü baştan sona düzgün ve eşit kalınlıkta kalır."}],"ans":"Her basamakta sabit genişlik sağlanır, DNA düzgün kalınlıkta kalır."},{"q":"Adenin bazı RNA da hangi bazla eşleşir, DNA dakinden farkı nedir?","steps":[{"t":"DNA daki eşleşmeyi hatırla","a":"DNA da A timinle eşleşir","d":"DNA da adenin her zaman timinle (A-T) eşleşir. Timin yalnızca DNA da bulunan bir bazdır."},{"t":"RNA daki durumu söyle","a":"RNA da A urasille eşleşir","d":"RNA da timin yerine urasil (U) bazı bulunur. Bu yüzden RNA da adenin urasille (A-U) eşleşir, kuralın diğer kısmı (G-C) aynı kalır."}],"ans":"RNA da adenin urasille eşleşir (timin yerine urasil bulunur)."},{"q":"DNA nın iki ipliği birbirine antiparalel uzanır. Bu kısaca ne demektir?","steps":[{"t":"İplik yönlerini düşün","a":"İpliklerin uçları farklıdır","d":"DNA ipliklerinin birer 5' ve birer 3' ucu vardır. Bu uçlar ipliğin yönünü belirler."},{"t":"Antiparalel yapıyı açıkla","a":"İplikler ters yönlüdür","d":"Antiparalel, iki ipliğin zıt yönlerde uzanması demektir. Bir iplik 5' den 3' e giderken, karşı iplik 3' den 5' e doğru uzanır."}],"ans":"İki iplik zıt yönlü (biri 5'→3', diğeri 3'→5') uzanır."},{"q":"Bir DNA ipliğinde 8 adenin varsa, çift iplikli molekülde toplam kaç A-T bağı (hidrojen bağı) bulunur?","steps":[{"t":"A-T çift sayısını bul","a":"8 adenin = 8 A-T çifti","d":"Bir iplikte 8 adenin varsa karşılarında 8 timin bulunur. Böylece 8 tane A-T baz çifti oluşur."},{"t":"Bağ sayısını hesapla","a":"Her A-T çifti 2 bağ taşır","d":"Her A-T çiftinde 2 hidrojen bağı vardır. 8 çift için 8 × 2 = 16 hidrojen bağı olur."}],"ans":"16 hidrojen bağı bulunur (8 çift × 2)."},{"q":"Tamamlayıcı baz eşleşmesi, DNA nın doğru kopyalanmasını nasıl sağlar?","steps":[{"t":"Eşleşme kuralını hatırla","a":"Her baz sadece çiftiyle eşleşir","d":"A yalnızca T ile, G yalnızca C ile eşleşir. Bu kural her zaman aynı şekilde işler."},{"t":"Kopyalamaya bağla","a":"Eski iplik kalıp görevi görür","d":"Eşlenme sırasında ayrılan her eski iplik bir kalıp gibi davranır. Kurallar gereği karşısına doğru bazlar dizilir, böylece yeni iplik hatasız oluşturulur."}],"ans":"Her bazın tek çifti olduğundan eski iplik yeni ipliğin dizisini doğru belirler."},{"q":"Chargaff in çalışmaları DNA yapısının çözülmesine nasıl katkı sağlamıştır?","steps":[{"t":"Chargaff bulgusunu hatırla","a":"A=T ve G=C oranları bulundu","d":"Chargaff farklı canlıların DNA larında adenin miktarının timine, guaninin sitozine eşit olduğunu ölçmüştür. Bu düzenli oranlar dikkat çekmiştir."},{"t":"Katkıyı açıkla","a":"Eşleşme fikrine ipucu verdi","d":"Bu eşitlikler bazların gelişigüzel değil, çiftler halinde bulunduğunu düşündürdü. Watson ve Crick bu bilgiyi A-T ve G-C eşleşmesini açıklamak için kullandı."}],"ans":"A=T, G=C oranları bazların çiftler halinde eşleştiği fikrine yol açtı."},{"q":"DNA da G-C içeriği yüksek bölgeler neden A-T içeriği yüksek bölgelerden daha kararlıdır?","steps":[{"t":"Bağ sayılarını karşılaştır","a":"G≡C 3, A=T 2 bağ","d":"Guanin-sitozin çifti 3 hidrojen bağı, adenin-timin çifti 2 hidrojen bağı taşır. Bağ sayıları farklıdır."},{"t":"Kararlılığa bağla","a":"Çok bağ daha kararlı yapı","d":"Hidrojen bağı sayısı arttıkça baz çiftleri daha sıkı tutunur. G-C zengini bölgeler daha çok bağ içerdiği için ayrılmaları daha çok enerji ister."}],"ans":"G≡C 3 bağ, A=T 2 bağ taşır; daha fazla bağ daha kararlı yapı sağlar."},{"q":"Bir DNA da toplam baz sayısı 200 ve adenin sayısı 40 ise guanin sayısını bul.","steps":[{"t":"A ve T yi belirle","a":"A=40 ise T=40","d":"Chargaff kuralına göre adenin timine eşittir. Adenin 40 olduğundan timin de 40 olur, toplamda 80 baz eder."},{"t":"G+C toplamını bul","a":"200 - 80 = 120","d":"Toplam 200 bazdan adenin ve timin çıkarılır. Geriye guanin ve sitozin için 120 baz kalır."},{"t":"Guanini hesapla","a":"G=C olduğundan 120/2=60","d":"Guanin sitozine eşittir. 120 bazın yarısı guanin, yarısı sitozin olduğundan guanin sayısı 60 olur."}],"ans":"Guanin sayısı 60 tır."}],"zor":[{"q":"Bir DNA molekülünde adenin %15 ise diğer üç bazın yüzdelerini Chargaff kuralıyla bulunuz.","steps":[{"t":"A ve T yi eşitle","a":"A %15 ise T %15","d":"Chargaff kuralına göre adenin timine eşittir. Adenin %15 olduğundan timin de %15 olur."},{"t":"A+T toplamını çıkar","a":"A+T = %30, G+C = %70","d":"Adenin ve timin toplamı %30 eder. Tüm bazlar %100 olduğundan guanin ve sitozine %70 kalır."},{"t":"G ve C yi paylaştır","a":"G=C=%35","d":"Guanin sitozine eşit olduğundan %70 ikiye bölünür. Buna göre guanin %35 ve sitozin %35 olur."}],"ans":"A=%15, T=%15, G=%35, C=%35."},{"q":"Bir DNA ipliğinin dizisi 5'-A-T-G-C-C-G-T-A-3' tür. Tamamlayıcı ipliği uygun yön göstererek yazınız.","steps":[{"t":"Eşleşme kurallarını belirle","a":"A-T, T-A, G-C, C-G","d":"Her bazın çifti yazılır. Adenin timinle, timin adeninle, guanin sitozinle ve sitozin guaninle eşleşir."},{"t":"Bazları sırayla eşle","a":"T-A-C-G-G-C-A-T","d":"Verilen 5'→3' dizisindeki her baz tek tek eşlenir. Sırayla T, A, C, G, G, C, A ve T elde edilir."},{"t":"Yönü ekle","a":"İplik antiparalel olmalı","d":"Tamamlayıcı iplik ters yönlüdür; verilen iplik 5'→3' ise diğeri 3'→5' tir. Tamamlayıcı iplik 3'-T-A-C-G-G-C-A-T-5' biçiminde yazılır."}],"ans":"Tamamlayıcı iplik 3'-T-A-C-G-G-C-A-T-5' olur."},{"q":"Bir çift iplikli DNA da 120 adenin ve 80 guanin bulunuyor. Bu molekülde toplam kaç hidrojen bağı vardır?","steps":[{"t":"Çiftleri belirle","a":"120 A-T çifti, 80 G-C çifti","d":"Her adenin bir timinle, her guanin bir sitozinle eşleşir. Böylece 120 A-T çifti ve 80 G-C çifti oluşur."},{"t":"A-T bağlarını hesapla","a":"120 × 2 = 240 bağ","d":"Her A-T çiftinde 2 hidrojen bağı bulunur. 120 çift için 120 × 2 = 240 hidrojen bağı olur."},{"t":"G-C bağlarını hesapla ve topla","a":"80 × 3 = 240; toplam 480","d":"Her G-C çiftinde 3 hidrojen bağı vardır. 80 × 3 = 240 bağ olur ve A-T bağlarıyla toplanınca 240 + 240 = 480 bağ elde edilir."}],"ans":"Toplam 480 hidrojen bağı vardır."},{"q":"Bir DNA bölgesinin denatürasyonu (ipliklerin ayrılması) için gereken sıcaklığı, baz içeriğiyle ilişkilendiriniz.","steps":[{"t":"Denatürasyonu tanımla","a":"Isı bazları ayırır","d":"Denatürasyon, sıcaklık etkisiyle hidrojen bağlarının kopup iki ipliğin ayrılmasıdır. Bunun için bağları kıracak kadar enerji gerekir."},{"t":"Baz içeriğiyle ilişkilendir","a":"G-C zengini bölge daha çok bağ taşır","d":"G≡C çifti 3, A=T çifti 2 hidrojen bağı taşır. G-C oranı yüksek bölgelerde toplam bağ sayısı daha fazladır."},{"t":"Sonucu açıkla","a":"G-C zengini bölge daha yüksek sıcaklık ister","d":"Daha çok hidrojen bağını koparmak daha çok enerji, yani daha yüksek sıcaklık gerektirir. Bu yüzden G-C bakımından zengin DNA daha yüksek sıcaklıkta ayrılır."}],"ans":"G-C içeriği arttıkça hidrojen bağı artar; ayrılma için daha yüksek sıcaklık gerekir."},{"q":"Bir DNA ipliğinde pürin sayısı 90, pirimidin sayısı 90 dır. Bu durum tamamlayıcı eşleşme açısından ne ifade eder?","steps":[{"t":"Pürin-pirimidin eşleşmesini hatırla","a":"Pürin daima pirimidinle eşleşir","d":"Çift iplikli DNA da her pürinin karşısında bir pirimidin bulunur. A-T ve G-C çiftlerinin ikisinde de bir pürin ve bir pirimidin vardır."},{"t":"Sayıları yorumla","a":"Toplam pürin = toplam pirimidin","d":"Çift iplikli DNA da toplam pürin sayısı her zaman toplam pirimidin sayısına eşittir. Burada her ikisi de 90 verilmiş, bu beklenen durumdur."},{"t":"Sonucu açıkla","a":"Eşitlik tamamlayıcılığın sonucudur","d":"Bu eşitlik, A+G = T+C demektir ve tamamlayıcı eşleşmenin doğal sonucudur. Her büyük baz bir küçük bazla eşleştiği için sayılar dengelenir."}],"ans":"Toplam pürin = toplam pirimidin olması, tamamlayıcı eşleşmenin doğal sonucudur (A+G=T+C)."},{"q":"Bir DNA da timin %22 ölçülmüştür. Guanin yüzdesini hesaplayınız.","steps":[{"t":"A-T eşitliğini kullan","a":"T %22 ise A %22","d":"Chargaff kuralına göre adenin timine eşittir. Timin %22 olduğundan adenin de %22 olur."},{"t":"A+T toplamını bul","a":"A+T = %44","d":"Adenin ve timin yüzdeleri toplanır. %22 + %22 = %44 eder, geriye G+C için %56 kalır."},{"t":"Guanini hesapla","a":"G = %56 / 2 = %28","d":"Guanin sitozine eşit olduğundan %56 ikiye bölünür. Buna göre guanin %28 ve sitozin %28 olur."}],"ans":"Guanin yüzdesi %28 dir."},{"q":"Eğer bir mutasyonla A bazının karşısına yanlışlıkla C bazı gelirse ne tür bir sorun ortaya çıkar?","steps":[{"t":"Doğru eşleşmeyi hatırla","a":"A normalde T ile eşleşir","d":"DNA da adenin yalnızca timinle 2 hidrojen bağı kurarak eşleşir. Bu yapısal olarak uyumlu bir eşleşmedir."},{"t":"Yanlış eşleşmeyi incele","a":"A-C uyumsuz bir çifttir","d":"Adenin ile sitozin doğru hidrojen bağı geometrisi oluşturamaz. Bu hatalı eşleşme baz çiftinde bir uyumsuzluk (yanlış eşleşme) meydana getirir."},{"t":"Sonucu açıkla","a":"Mutasyona yol açabilir","d":"Hatalı eşleşme onarılmazsa, sonraki replikasyonda yanlış baz dizisi kalıcı hale gelir. Bu, baz dizisini değiştiren bir nokta mutasyonuna neden olabilir."}],"ans":"A-C uyumsuz bir eşleşmedir; onarılmazsa nokta mutasyonuna yol açar."},{"q":"Bir DNA molekülünde toplam 1000 baz çifti vardır ve bunların %40 ı G-C çiftidir. Toplam hidrojen bağı sayısını bulunuz.","steps":[{"t":"Çift sayılarını ayır","a":"G-C %40 = 400, A-T = 600","d":"Toplam 1000 baz çiftinin %40 ı G-C dir, bu 400 çift eder. Geriye kalan 600 çift A-T dir."},{"t":"G-C bağlarını hesapla","a":"400 × 3 = 1200 bağ","d":"Her G-C çiftinde 3 hidrojen bağı vardır. 400 çift için 400 × 3 = 1200 bağ olur."},{"t":"A-T bağlarını ekle","a":"600 × 2 = 1200; toplam 2400","d":"Her A-T çiftinde 2 hidrojen bağı vardır. 600 × 2 = 1200 bağ olur ve G-C bağlarıyla toplanınca 1200 + 1200 = 2400 bağ elde edilir."}],"ans":"Toplam 2400 hidrojen bağı vardır."},{"q":"Bir DNA ipliğinde 5'-G-G-A-T-C-C-3' dizisi var. Bu dizinin tamamlayıcısını yazıp diziyle karşılaştırınız.","steps":[{"t":"Tamamlayıcıyı oluştur","a":"C-C-T-A-G-G","d":"Verilen 5'→3' dizinin her bazı eşlenir: G-C, G-C, A-T, T-A, C-G, C-G. Tamamlayıcı 3'-C-C-T-A-G-G-5' olur."},{"t":"Tamamlayıcıyı 5'→3' yönünde yaz","a":"Tersten okununca G-G-A-T-C-C","d":"Tamamlayıcı iplik 5'→3' yönünde okunduğunda dizi G-G-A-T-C-C olur. Bu, başlangıçtaki diziyle aynıdır."},{"t":"Karşılaştır","a":"Dizi palindromiktir","d":"İki iplik aynı 5'→3' diziyi verdiği için bu bölge palindromik bir dizidir. Bu tür diziler bazı enzimlerin tanıdığı özel bölgelerdir."}],"ans":"Tamamlayıcı 5'→3' okununca G-G-A-T-C-C; dizi palindromiktir."},{"q":"Bir virüsün tek iplikli DNA sında A %30, T %25 ölçülmüştür. Bu sonuç Chargaff kuralıyla neden çelişmez?","steps":[{"t":"Chargaff kuralının koşulunu hatırla","a":"Kural çift iplikli DNA için geçerlidir","d":"Chargaff kuralındaki A=T ve G=C eşitlikleri, bazların karşılıklı eşleştiği çift iplikli DNA için söz konusudur. Eşleşme olmadan bu eşitlik gerekmez."},{"t":"Tek iplikli yapıyı incele","a":"Tek iplikte eşleşme yoktur","d":"Tek iplikli DNA da bazlar bir başka iplikle eşleşmez. Bu yüzden adenin ve timin sayılarının birbirine eşit olması zorunlu değildir."},{"t":"Sonucu açıkla","a":"A≠T olması beklenir","d":"Tek iplikte A %30, T %25 olması doğaldır ve kurala aykırı değildir. Chargaff eşitliği yalnızca tamamlayıcı iki ipliğin bir arada bulunduğu durumda geçerlidir."}],"ans":"Chargaff kuralı çift iplikli DNA için geçerlidir; tek iplikte A≠T olabilir."},{"q":"Bir DNA bölgesinde A-T çiftleri G-C çiftlerinin 3 katıdır ve toplam 800 baz çifti vardır. Hidrojen bağı toplamını bulunuz.","steps":[{"t":"Çift sayılarını kur","a":"G-C = x, A-T = 3x","d":"G-C çift sayısına x dersek A-T çiftleri 3x olur. Toplam çift sayısı x + 3x = 4x tir."},{"t":"x i bul","a":"4x = 800, x = 200","d":"Toplam çift 800 olduğundan 4x = 800 olur. Buradan x = 200 bulunur; yani 200 G-C ve 600 A-T çifti vardır."},{"t":"Bağları hesapla","a":"200×3 + 600×2 = 1800","d":"G-C çiftleri 200 × 3 = 600 bağ, A-T çiftleri 600 × 2 = 1200 bağ verir. Toplam 600 + 1200 = 1800 hidrojen bağı olur."}],"ans":"Toplam 1800 hidrojen bağı vardır."},{"q":"DNA çift sarmalında baz çiftlerinin sarmalın iç kısmında, şeker-fosfat omurgasının ise dışta bulunması neden mantıklıdır?","steps":[{"t":"Bazların özelliğini düşün","a":"Bazlar suyu sevmez (hidrofobik)","d":"Azotlu bazlar suya karşı itici (hidrofobik) eğilimdedir. Bu yüzden sudan uzak, korunaklı bir konumda durmaları kararlılığı artırır."},{"t":"Omurganın özelliğini düşün","a":"Fosfatlar suyu sever (hidrofilik)","d":"Şeker-fosfat omurgası negatif yüklü fosfat grupları içerir ve suyla etkileşmeyi sever (hidrofilik). Bu kısmın dışta, su ortamına dönük olması uygundur."},{"t":"Sonucu açıkla","a":"Yapı kararlı ve korunaklı olur","d":"Bazlar içte istiflenerek hidrojen bağları ve baz istiflenmesiyle korunur, omurga dışta suyla etkileşir. Bu yerleşim molekülü hem kararlı hem de hücre içi su ortamına uyumlu kılar."}],"ans":"Hidrofobik bazlar içte korunur, hidrofilik omurga dışta suyla etkileşir; bu kararlılık sağlar."},{"q":"İki DNA örneğinden birinde G-C oranı %60, diğerinde %40 tır. Hangisinin baz çiftleri ortalama daha çok hidrojen bağı taşır, açıklayınız.","steps":[{"t":"Bağ sayılarını hatırla","a":"G-C 3, A-T 2 bağ","d":"Guanin-sitozin çifti 3, adenin-timin çifti 2 hidrojen bağı taşır. Bir bölgede G-C oranı arttıkça baz çifti başına ortalama bağ sayısı yükselir."},{"t":"Örnekleri karşılaştır","a":"%60 G-C li örnek daha çok bağ taşır","d":"G-C oranı %60 olan örnekte üç bağlı çiftler daha fazladır. Bu yüzden ortalama hidrojen bağı sayısı, %40 G-C li örnekten yüksektir."},{"t":"Sonucu açıkla","a":"Daha kararlı ve ayrılması zor","d":"Daha çok hidrojen bağı taşıyan örnek daha kararlıdır ve iplikleri daha zor ayrılır. Bu nedenle %60 G-C li DNA daha yüksek sıcaklıkta denatüre olur."}],"ans":"%60 G-C li örnek; G-C 3 bağ taşıdığı için ortalama bağ sayısı daha yüksektir."},{"q":"Bir DNA ipliğinde 200 baz vardır; bunların 60 ı adenin, 40 ı sitozindir. Karşı iplikteki guanin sayısını bulunuz.","steps":[{"t":"İlk ipliğin bazlarını topla","a":"A=60, C=40, kalan=100","d":"Tek iplikte 200 baz var; 60 adenin ve 40 sitozin verilmiş. Geriye timin ve guanin için toplam 100 baz kalır, ancak soru karşı ipliği soruyor."},{"t":"Eşleşmeyi karşı ipliğe uygula","a":"Bu ipliğin C si karşıda G ile eşleşir","d":"Tamamlayıcı eşleşmeye göre bu iplikteki her sitozinin karşısında bir guanin bulunur. Bu iplikte 40 sitozin olduğundan karşı iplikte 40 guanin yer alır."},{"t":"Sonucu yaz","a":"Karşı iplikte 40 guanin","d":"Bu iplikteki 40 sitozin, karşı iplikte 40 guanine karşılık gelir. Dolayısıyla karşı ipliğin guanin sayısı 40 tır."}],"ans":"Karşı iplikte 40 guanin bulunur."},{"q":"Bir DNA molekülünde adenin ile guanin oranı (A/G) 2 dir ve toplam baz sayısı 600 dür. Her bazın sayısını bulunuz.","steps":[{"t":"Eşitlikleri kur","a":"A=T, G=C, A=2G","d":"Chargaff kuralı gereği A=T ve G=C dir. Ayrıca A/G = 2 olduğundan A = 2G yazılır."},{"t":"Toplam denklemini yaz","a":"A+T+G+C = 600","d":"Tüm bazların toplamı 600 dür. Eşitlikler yerine konursa 2G + 2G + G + G = 600, yani 6G = 600 olur."},{"t":"Sayıları çöz","a":"G=100, A=200","d":"6G = 600 ten G = 100 bulunur, dolayısıyla C de 100 dür. A = 2G = 200 olur ve T de 200 dür."}],"ans":"A=200, T=200, G=100, C=100."}]}},"replikasyon":{"ilkokul":{"kolay":[{"q":"DNA nın kendi kopyasını oluşturmasına ne ad verilir?","steps":[{"t":"Olayı tanımla","a":"DNA kendini ikiye çoğaltır","d":"Hücre bölünmeden önce DNA kendi kopyasını çıkarır. Böylece bir DNA dan iki tane DNA oluşur."},{"t":"Adını söyle","a":"Bu olaya eşlenme denir","d":"DNA nın kendini kopyalamasına eşlenme (replikasyon) denir. Bu sayede her yeni hücre DNA sını alır."}],"ans":"Bu olaya eşlenme (replikasyon) denir."},{"q":"Hücre bölünmeden önce DNA neden kopyalanır?","steps":[{"t":"Bölünmeyi düşün","a":"Bir hücre ikiye bölünür","d":"Hücreler çoğalırken bir hücre ikiye bölünür. Oluşan her yeni hücrenin de DNA ya ihtiyacı vardır."},{"t":"Nedeni söyle","a":"Her hücreye DNA yetsin diye","d":"DNA kopyalanmazsa yeni hücrelerden birine DNA düşmez. Bu yüzden bölünmeden önce DNA kopyalanır ki her hücreye eşit pay düşsün."}],"ans":"Her yeni hücreye eksiksiz DNA verebilmek için kopyalanır."},{"q":"Bir DNA eşlendiğinde kaç tane DNA oluşur?","steps":[{"t":"Eşlenmeyi düşün","a":"DNA kendini bir kez kopyalar","d":"Eşlenme sırasında DNA kendinin bir kopyasını çıkarır. Yani eski DNA nın bir benzeri daha yapılır."},{"t":"Sayıyı söyle","a":"Bir DNA dan iki DNA olur","d":"Eşlenme sonunda başlangıçtaki bir DNA dan birbirinin aynısı iki DNA oluşur. Böylece DNA sayısı ikiye katlanır."}],"ans":"Bir DNA dan iki DNA oluşur."},{"q":"Eşlenmede yeni oluşan DNA, eski DNA ya benzer mi yoksa farklı mı olur?","steps":[{"t":"Kopyalamayı düşün","a":"DNA aynı kurallarla kopyalanır","d":"Eşlenmede bazlar kurallara göre yerleştirilir. Bu yüzden yeni DNA gelişigüzel değil, belirli bir düzende oluşur."},{"t":"Benzerliği söyle","a":"Yeni DNA eskinin aynısıdır","d":"Doğru eşlenme sonunda yeni DNA eski DNA ile aynı bilgileri taşır. Yani iki DNA birbirinin tıpatıp aynısı olur."}],"ans":"Yeni DNA, eski DNA nın tıpatıp aynısı olur."},{"q":"Eşlenme sırasında DNA nın iki ipliği ne yapar?","steps":[{"t":"Başlangıcı düşün","a":"İki iplik birbirinden ayrılır","d":"Eşlenmenin başında DNA nın birbirine sarılı iki ipliği açılır. Bu, bir fermuarın açılmasına benzer."},{"t":"Sonucu söyle","a":"Her iplik kalıp olur","d":"Ayrılan her iplik, yeni iplik yapımı için bir örnek (kalıp) görevi görür. Her eski ipliğin karşısına yeni bir iplik yapılır."}],"ans":"İki iplik birbirinden ayrılır ve her biri yeni iplik için kalıp olur."}],"zor":[{"q":"Eşlenmede oluşan her yeni DNA da bir eski bir yeni iplik bulunur. Bir DNA dan iki DNA oluşunca toplam kaç eski iplik vardır?","steps":[{"t":"Başlangıçtaki iplikleri say","a":"İlk DNA da 2 eski iplik var","d":"Eşlenmeden önce DNA iki iplikten oluşur ve bu iplikler eskidir. Yani başlangıçta 2 eski iplik vardır."},{"t":"Eski iplikleri izle","a":"Eski iplikler kaybolmaz","d":"Eşlenmede eski iplikler yok olmaz, sadece yeni ipliklerle eşleşir. Her yeni DNA da eski ipliklerden biri kullanılır."},{"t":"Toplamı söyle","a":"Hâlâ 2 eski iplik vardır","d":"İki DNA oluşsa da eski iplik sayısı değişmez. Başlangıçtaki 2 eski iplik iki DNA ya dağılmış olarak durur."}],"ans":"Toplam 2 eski iplik vardır (her yeni DNA da bir tane)."},{"q":"Eşlenme hücrenin hangi anında, bölünmeden önce mi sonra mı yapılır? Nedenini açıkla.","steps":[{"t":"Bölünme ihtiyacını düşün","a":"Bölünmede DNA paylaşılır","d":"Hücre bölündüğünde DNA iki yeni hücreye paylaştırılır. Bu yüzden bölünme anında yeterli DNA bulunmalıdır."},{"t":"Zamanı belirle","a":"Eşlenme bölünmeden önce olur","d":"DNA önce kopyalanır, sonra hücre bölünür. Böylece bölünme sırasında her hücreye tam bir DNA düşer."}],"ans":"Eşlenme bölünmeden önce olur; her hücreye tam DNA düşsün diye."},{"q":"Eğer DNA eşlenmeden hücre bölünseydi yeni hücreler için ne sorun olurdu?","steps":[{"t":"DNA paylaşımını düşün","a":"Tek DNA ikiye bölünemez","d":"Eşlenme olmazsa bölünme anında elde sadece bir DNA bulunur. Bu tek DNA iki hücreye tam olarak verilemez."},{"t":"Sonucu söyle","a":"Bir hücre eksik DNA alır","d":"DNA paylaştırıldığında hücrelerden biri yeterli kalıtım bilgisi alamaz. Eksik DNA lı hücre düzgün çalışamaz veya yaşayamaz."}],"ans":"Hücrelerden biri eksik DNA alır ve düzgün çalışamaz."},{"q":"Eşlenmede yeni iplikler nasıl doğru bazlarla yapılır?","steps":[{"t":"Kalıp ipliği düşün","a":"Eski iplik örnek alınır","d":"Eşlenmede ayrılan eski iplik bir kalıp gibi kullanılır. Yeni iplik bu kalıba bakılarak yapılır."},{"t":"Eşleşme kuralını uygula","a":"A-T, G-C kuralına uyulur","d":"Kalıp iplikteki her bazın karşısına çifti yerleştirilir; A nın karşısına T, G nin karşısına C gelir. Bu kural sayesinde yeni iplik doğru bazlarla oluşur."}],"ans":"Eski iplik kalıp olur, bazlar A-T ve G-C kuralına göre dizilir."},{"q":"Bir hücre bölünüp 2 hücre olacaksa, başta 1 olan DNA sayısı bölünmeden önce kaça çıkmalıdır?","steps":[{"t":"Her hücrenin ihtiyacını düşün","a":"Her hücre 1 DNA ister","d":"Bölünme sonunda oluşacak her hücrenin birer DNA ya ihtiyacı vardır. 2 hücre için 2 DNA gerekir."},{"t":"Gerekli sayıyı bul","a":"DNA 1 den 2 ye çıkar","d":"Eşlenme sayesinde DNA bölünmeden önce kopyalanır. Böylece 1 olan DNA sayısı 2 ye çıkar ve her hücreye birer DNA düşer."}],"ans":"DNA sayısı bölünmeden önce 2 ye çıkmalıdır."}]},"ortaokul":{"kolay":[{"q":"DNA eşlenmesi (replikasyon) için yarı korunumlu model ne anlama gelir?","steps":[{"t":"Yeni DNA nın yapısını düşün","a":"Her yeni DNA da bir eski iplik var","d":"Eşlenme sonunda oluşan her DNA da ipliklerden biri eskidir, diğeri yenidir. Eski iplik korunarak yeni DNA ya aktarılır."},{"t":"Modeli adlandır","a":"Bu modele yarı korunumlu denir","d":"Eski ipliğin yarısının korunup yenisinin eklenmesi nedeniyle bu modele yarı korunumlu model denir. Yani her DNA yarı eski yarı yenidir."}],"ans":"Her yeni DNA da bir eski bir yeni iplik bulunmasıdır."},{"q":"DNA eşlenmesi hücre döngüsünün hangi evresinde gerçekleşir?","steps":[{"t":"Evreyi hatırla","a":"DNA bölünmeden önce kopyalanır","d":"Hücre bölünmeden önce DNA sını çoğaltır. Bu kopyalama belirli bir evrede yapılır."},{"t":"Evrenin adını söyle","a":"S evresinde gerçekleşir","d":"DNA eşlenmesi hücre döngüsünün S (sentez) evresinde olur. Bu evrede DNA miktarı iki katına çıkar."}],"ans":"DNA eşlenmesi S (sentez) evresinde gerçekleşir."},{"q":"Eşlenme başlarken DNA nın iki ipliğini ayıran nedir?","steps":[{"t":"İpliklerin nasıl tutunduğunu hatırla","a":"İplikler hidrojen bağlarıyla bağlı","d":"DNA nın iki ipliği bazlar arasındaki hidrojen bağlarıyla tutunur. Eşlenme için bu bağların açılması gerekir."},{"t":"Ayırıcıyı söyle","a":"Enzimler iplikleri ayırır","d":"Özel enzimler hidrojen bağlarını açarak iki ipliği birbirinden ayırır. Böylece her iplik kalıp olarak kullanılabilir hale gelir."}],"ans":"Enzimler hidrojen bağlarını açarak iki ipliği ayırır."},{"q":"Bir DNA eşlendiğinde oluşan iki DNA birbirine göre nasıldır?","steps":[{"t":"Eşlenme kuralını hatırla","a":"Kalıba göre kopyalama yapılır","d":"Eşlenmede her eski iplik kalıp olur ve baz eşleşme kurallarına göre yeni iplik eklenir. İşlem belirli kurallarla yürür."},{"t":"Sonucu söyle","a":"İki DNA birbirinin aynısıdır","d":"Doğru eşlenmede oluşan iki DNA da aynı baz dizisini taşır. Bu yüzden iki DNA birbirinin tıpatıp aynısı (özdeş) olur."}],"ans":"Oluşan iki DNA birbirinin tıpatıp aynısıdır (özdeştir)."},{"q":"DNA eşlenmesi olmasaydı çok hücreli bir canlı büyüyebilir miydi?","steps":[{"t":"Büyümeyi düşün","a":"Büyüme yeni hücrelerle olur","d":"Canlılar yeni hücreler üreterek büyür. Yeni hücreler hücre bölünmesiyle oluşur."},{"t":"Eşlenme ile ilişkilendir","a":"Bölünme için DNA kopyası şart","d":"Her bölünmeden önce DNA eşlenmelidir ki yeni hücrelere tam DNA düşsün. Eşlenme olmazsa hücreler bölünemez ve canlı büyüyemez."}],"ans":"Hayır; eşlenme olmadan hücreler bölünemez, canlı büyüyemezdi."}],"zor":[{"q":"Bir DNA bir kez eşlendiğinde, her yeni DNA nın iplik yapısını yarı korunumlu modele göre açıklayınız.","steps":[{"t":"Başlangıcı düşün","a":"2 eski iplik kalıp olur","d":"Eşlenmeden önce DNA da 2 eski iplik vardır. Bu iplikler ayrılarak her biri yeni iplik için kalıp görevi görür."},{"t":"Yeni iplikleri ekle","a":"Her kalıba 1 yeni iplik yapılır","d":"Her eski ipliğin karşısına baz eşleşme kurallarıyla yeni bir iplik sentezlenir. Böylece eski iplik ile yeni iplik birlikte bir DNA oluşturur."},{"t":"Sonucu açıkla","a":"Her DNA yarı eski yarı yeni","d":"Oluşan iki DNA nın her birinde bir eski bir yeni iplik bulunur. Bu yüzden modele yarı korunumlu denir."}],"ans":"Her yeni DNA bir eski (kalıp) ve bir yeni iplikten oluşur; yarı korunumludur."},{"q":"Bir hücredeki DNA iki kez art arda eşlenirse en sonunda kaç DNA molekülü oluşur?","steps":[{"t":"İlk eşlenmeyi hesapla","a":"1 DNA → 2 DNA","d":"Birinci eşlenmede başlangıçtaki bir DNA dan iki DNA oluşur. DNA sayısı ikiye katlanır."},{"t":"İkinci eşlenmeyi hesapla","a":"2 DNA → 4 DNA","d":"İkinci eşlenmede mevcut iki DNA nın her biri yine ikiye katlanır. Böylece toplam 2 × 2 = 4 DNA olur."}],"ans":"İki eşlenme sonunda 4 DNA molekülü oluşur."},{"q":"DNA eşlenmesi neden hücre bölünmesinden hemen önce (S evresinde) yapılmalıdır?","steps":[{"t":"Bölünme ihtiyacını hatırla","a":"Her hücreye tam DNA gerekir","d":"Hücre bölündüğünde DNA iki hücreye paylaştırılır. Her hücrenin eksiksiz bir DNA ya ihtiyacı vardır."},{"t":"Zamanlamayı açıkla","a":"Önce kopya, sonra bölünme","d":"DNA bölünmeden önce S evresinde kopyalanır. Böylece bölünme anında paylaştırılacak yeterli DNA hazır olur."},{"t":"Sonucu söyle","a":"İki hücre de eşit DNA alır","d":"Önceden eşlenme yapıldığı için bölünmede her hücreye birer tam DNA düşer. Bu sayede kalıtım bilgisi eksiksiz aktarılır."}],"ans":"Bölünmede her hücreye tam DNA düşsün diye, kopyalama bölünmeden önce yapılır."},{"q":"Eşlenmede ortaya çıkan bir baz hatası onarılmazsa hangi sonuca yol açabilir?","steps":[{"t":"Hatayı tanımla","a":"Yanlış baz eklenebilir","d":"Eşlenme sırasında bazen kalıba uymayan yanlış bir baz eklenebilir. Bu, DNA dizisinde bir hata oluşturur."},{"t":"Onarımsız durumu düşün","a":"Hata kalıcı hale gelir","d":"Hata onarılmazsa sonraki eşlenmede bu yanlış dizi aynen kopyalanır. Böylece hata yeni DNA larda kalıcılaşır."},{"t":"Sonucu söyle","a":"Mutasyon oluşur","d":"Kalıcı hale gelen baz değişikliğine mutasyon denir. Mutasyonlar bazen proteinlerin yapısını ve hücrenin çalışmasını etkileyebilir."}],"ans":"Onarılmayan hata kalıcı bir mutasyona yol açabilir."},{"q":"Eşlenme sırasında yeni ipliğin doğru dizilmesini sağlayan temel ilke nedir, açıklayınız.","steps":[{"t":"Kalıp ipliği hatırla","a":"Eski iplik kalıp görevi görür","d":"Eşlenmede ayrılan her eski iplik bir örnek (kalıp) olarak kullanılır. Yeni iplik bu kalıbın bazlarına göre yapılır."},{"t":"Eşleşme kuralını uygula","a":"A-T ve G-C kuralı işler","d":"Kalıptaki her bazın karşısına tamamlayıcı baz eklenir; A karşısına T, G karşısına C gelir. Bu tamamlayıcılık ilkesi diziyi belirler."},{"t":"Sonucu açıkla","a":"Doğru kopya garanti edilir","d":"Her bazın tek bir çifti olduğu için yeni iplik kalıba göre kesin biçimde oluşur. Böylece kopya, aslına sadık ve hatasız olur."}],"ans":"Tamamlayıcı baz eşleşmesi (A-T, G-C); kalıba göre doğru iplik dizilir."}]},"lise":{"kolay":[{"q":"DNA replikasyonunun yarı korunumlu olması ne demektir?","steps":[{"t":"Yeni DNA içeriğini incele","a":"Bir eski bir yeni iplik vardır","d":"Replikasyon sonunda oluşan her DNA molekülü, biri ana DNA dan gelen eski (kalıp) iplik, biri yeni sentezlenen iplik içerir. İki iplik birlikte yeni molekülü oluşturur."},{"t":"Modeli tanımla","a":"Yarısı korunur","d":"Ana molekülün ipliklerinin yarısı yeni moleküllere korunarak aktarılır. Bu nedenle modele yarı korunumlu (semikonservatif) denir."}],"ans":"Her yeni DNA bir eski (kalıp) ve bir yeni iplikten oluşur."},{"q":"DNA replikasyonu hücre döngüsünün hangi evresinde gerçekleşir?","steps":[{"t":"İnterfaz evrelerini hatırla","a":"İnterfaz G1, S, G2 den oluşur","d":"Hücre döngüsünde bölünme öncesi dönem interfaz olarak adlandırılır ve G1, S, G2 alt evrelerine ayrılır. DNA miktarındaki artış belirli bir evrede olur."},{"t":"Doğru evreyi seç","a":"DNA S evresinde kopyalanır","d":"DNA replikasyonu interfazın S (sentez) evresinde gerçekleşir. Bu evre sonunda hücredeki DNA miktarı iki katına çıkar."}],"ans":"İnterfazın S (sentez) evresinde gerçekleşir."},{"q":"Replikasyonda kalıp (şablon) iplik ne işe yarar?","steps":[{"t":"Kalıp kavramını tanımla","a":"Eski iplik örnek alınır","d":"Replikasyonda ayrılan her eski iplik bir kalıp (şablon) görevi görür. Yeni iplik bu kalıbın baz dizisine göre yapılır."},{"t":"İşlevini açıkla","a":"Yeni ipliğin dizisini belirler","d":"Kalıptaki bazlar, tamamlayıcı eşleşmeyle yeni ipliğin hangi bazları taşıyacağını belirler. Böylece yeni iplik kalıba uygun ve doğru biçimde sentezlenir."}],"ans":"Kalıp iplik, yeni ipliğin baz dizisini belirleyen örnektir."},{"q":"Replikasyon canlı için neden gereklidir?","steps":[{"t":"Bölünme ihtiyacını düşün","a":"Hücreler bölünerek çoğalır","d":"Büyüme, onarım ve üreme için hücreler bölünür. Bölünen her hücrenin kendi DNA sına ihtiyacı vardır."},{"t":"Gerekliliği açıkla","a":"Her hücreye DNA aktarılmalı","d":"Bölünmeden önce DNA kopyalanmazsa yeni hücreler eksik kalıtım bilgisiyle kalır. Replikasyon, kalıtsal bilginin eksiksiz aktarılmasını sağlar."}],"ans":"Bölünen her hücreye eksiksiz kalıtsal bilgi aktarmak için gereklidir."},{"q":"Replikasyon başlamadan önce DNA çift sarmalına ne olur?","steps":[{"t":"Sarmalın açılmasını düşün","a":"İplikler birbirinden ayrılır","d":"Replikasyonun başında çift sarmalın iki ipliği birbirinden ayrılır. Bu ayrılma, bazlar arasındaki hidrojen bağlarının kopmasıyla olur."},{"t":"Sonucu açıkla","a":"Her iplik kalıp olur","d":"Ayrılan iki iplik açılarak kalıp haline gelir. Her bir iplik kendi yeni eşini sentezlemek için şablon olarak kullanılır."}],"ans":"Çift sarmal açılır, iplikler ayrılır ve her biri kalıp olur."},{"q":"Bir DNA molekülü bir kez replike olduğunda kaç DNA molekülü oluşur?","steps":[{"t":"Replikasyonu hatırla","a":"DNA kendinin kopyasını yapar","d":"Bir replikasyon turunda DNA kendinin tam bir kopyasını oluşturur. İki kalıp ipliğin her biri yeni bir iplikle tamamlanır."},{"t":"Sayıyı belirt","a":"1 DNA → 2 DNA","d":"Bir replikasyon sonunda başlangıçtaki bir DNA dan birbirinin özdeşi iki DNA molekülü oluşur. DNA sayısı ikiye katlanır."}],"ans":"Bir replikasyonla 2 özdeş DNA molekülü oluşur."},{"q":"Replikasyon sonucu oluşan iki DNA molekülü neden birbirinin aynısıdır?","steps":[{"t":"Kalıp kullanımını hatırla","a":"İki kalıp aynı DNA dandır","d":"Replikasyonda kullanılan iki kalıp iplik, aynı ana DNA nın birbirini tamamlayan iplikleridir. Bu yüzden ikisi de aynı bilgiyi farklı biçimde taşır."},{"t":"Eşleşmeye bağla","a":"Tamamlayıcı eşleşme aynı diziyi verir","d":"Her kalıba A-T ve G-C kuralıyla yeni iplik yapılınca, sonuçta ana DNA ile aynı baz dizisi yeniden oluşur. Böylece iki yeni DNA da özdeş olur."}],"ans":"Tamamlayıcı eşleşme sayesinde her kopya ana DNA ile aynı diziyi taşır."},{"q":"Replikasyonda iplikleri açan ve hidrojen bağlarını kıran enzimin görevi nedir?","steps":[{"t":"İpliklerin tutunmasını hatırla","a":"İplikler hidrojen bağıyla bağlı","d":"DNA nın iki ipliği bazlar arasındaki hidrojen bağlarıyla bir arada durur. Kopyalama için bu bağların açılması gerekir."},{"t":"Enzimin görevini söyle","a":"Helikaz iplikleri ayırır","d":"Helikaz enzimi hidrojen bağlarını kırarak iki ipliği birbirinden ayırır. Böylece replikasyon çatalı açılır ve kalıp iplikler ortaya çıkar."}],"ans":"Helikaz enzimi hidrojen bağlarını kırarak iplikleri ayırır."},{"q":"Yeni DNA ipliğine bazları (nükleotitleri) ekleyen enzimin adı nedir?","steps":[{"t":"İhtiyacı düşün","a":"Yeni iplik nükleotit gerektirir","d":"Açılan kalıp ipliğin karşısına yeni nükleotitlerin eklenmesi gerekir. Bu ekleme rastgele değil, kontrollü biçimde yapılır."},{"t":"Enzimi söyle","a":"DNA polimeraz nükleotit ekler","d":"DNA polimeraz enzimi, kalıba uygun nükleotitleri tamamlayıcı eşleşmeye göre yeni ipliğe ekler. Böylece yeni iplik kalıp boyunca uzar."}],"ans":"DNA polimeraz enzimi yeni ipliğe nükleotitleri ekler."},{"q":"Replikasyon, mitoz bölünme ile yeni hücrelerin genetik olarak aynı olmasını nasıl sağlar?","steps":[{"t":"Replikasyon sonucunu hatırla","a":"İki özdeş DNA oluşur","d":"Replikasyonda ana DNA dan iki özdeş DNA kopyası elde edilir. Bu kopyalar aynı kalıtsal bilgiyi taşır."},{"t":"Mitoza bağla","a":"Her hücreye birer kopya gider","d":"Mitozda bu özdeş kopyalardan biri her yeni hücreye paylaştırılır. Böylece oluşan iki hücre, ana hücreyle ve birbiriyle genetik olarak aynı olur."}],"ans":"Özdeş kopyalar üretilip her hücreye birer tane verildiğinden hücreler genetik olarak aynı olur."},{"q":"Replikasyonun yüksek doğrulukla yapılması canlı için neden önemlidir?","steps":[{"t":"Bilgi aktarımını düşün","a":"DNA kalıtsal bilgi taşır","d":"DNA, proteinlerin ve hücre işlevlerinin bilgisini taşır. Bu bilginin yeni hücrelere doğru aktarılması gerekir."},{"t":"Önemi açıkla","a":"Hatalar mutasyona yol açar","d":"Replikasyon hatalı olursa baz dizisi değişir ve mutasyonlar oluşur. Yüksek doğruluk, kalıtsal bilginin bozulmadan korunmasını ve hücrelerin sağlıklı çalışmasını sağlar."}],"ans":"Kalıtsal bilgi bozulmadan aktarılsın ve mutasyon en aza insin diye önemlidir."},{"q":"Replikasyon çatalı kavramı neyi ifade eder?","steps":[{"t":"İpliklerin açılmasını düşün","a":"İplikler bir noktadan ayrılır","d":"Replikasyonda DNA belirli bir noktadan açılmaya başlar ve iki iplik ayrılır. Açılan bölge ile kapalı bölge arasında Y şeklinde bir yapı oluşur."},{"t":"Çatalı tanımla","a":"Y şekilli açılma bölgesidir","d":"Bu Y biçimli, ipliklerin ayrıldığı ve yeni sentezin yapıldığı bölgeye replikasyon çatalı denir. Çatal, açılma ilerledikçe kalıp boyunca hareket eder."}],"ans":"İpliklerin ayrıldığı, yeni sentezin yapıldığı Y şekilli bölgedir."},{"q":"Bir DNA molekülünde replikasyon başladığında bir eski iplik ne kadar korunur?","steps":[{"t":"Yarı korunumlu modeli hatırla","a":"Eski iplik bütün halde kalır","d":"Yarı korunumlu modele göre ana DNA nın eski iplikleri bozulmadan korunur. Bu iplikler yeni moleküllere kalıp olarak geçer."},{"t":"Korunma miktarını söyle","a":"Her DNA da bir tam eski iplik","d":"Replikasyon sonunda oluşan her DNA da bir tam eski iplik bulunur. Yani eski iplik parçalanmadan, bütün olarak yeni moleküle aktarılır."}],"ans":"Eski iplik parçalanmaz; her yeni DNA ya bir tam eski iplik korunarak geçer."},{"q":"Replikasyon ile transkripsiyon (RNA sentezi) arasındaki en temel amaç farkı nedir?","steps":[{"t":"Replikasyonun amacını yaz","a":"DNA yı kopyalamak","d":"Replikasyonun amacı tüm DNA nın eksiksiz bir kopyasını çıkarmaktır. Sonuçta DNA dan DNA üretilir ve hücre bölünmesine hazırlanır."},{"t":"Transkripsiyonun amacını yaz","a":"RNA üretmek","d":"Transkripsiyonun amacı DNA daki bir genin bilgisini RNA ya aktarmaktır. Sonuçta DNA dan RNA üretilir ve genellikle tüm DNA değil belli bir bölge kopyalanır."},{"t":"Farkı özetle","a":"Biri DNA, diğeri RNA üretir","d":"Replikasyon DNA dan DNA, transkripsiyon ise DNA dan RNA üretir. Replikasyon kalıtımın aktarımı, transkripsiyon ise gen ifadesi içindir."}],"ans":"Replikasyon DNA dan DNA, transkripsiyon DNA dan RNA üretir."},{"q":"Replikasyonda yeni iplik sentezi neden mutlaka tamamlayıcı eşleşme kurallarına uyar?","steps":[{"t":"Eşleşme kuralını hatırla","a":"Her bazın tek çifti var","d":"DNA da A yalnızca T ile, G yalnızca C ile uyumlu hidrojen bağı kurar. Bu yapısal uyum kuralı değiştirilemez."},{"t":"Sentez sürecine bağla","a":"Polimeraz uygun bazı seçer","d":"DNA polimeraz, kalıptaki baza yalnızca tamamlayıcı olan nükleotidi ekleyebilir. Uyumsuz bir baz doğru bağ ve geometriyi sağlayamadığından kabul edilmez."},{"t":"Sonucu açıkla","a":"Kopya aslına sadık olur","d":"Tamamlayıcı kurala uyulduğu için yeni iplik kalıbı tam olarak yansıtır. Bu sayede oluşan DNA, ana DNA ile özdeş ve doğru olur."}],"ans":"Her bazın tek uyumlu çifti olduğundan, kurala uyulması kopyanın aslına sadık olmasını sağlar."}],"zor":[{"q":"Bir DNA molekülü üç kez art arda replike olursa toplam kaç DNA molekülü oluşur ve bunların kaçında orijinal eski iplik bulunur?","steps":[{"t":"Molekül sayısını hesapla","a":"2 üzeri 3 = 8 molekül","d":"Her replikasyon turunda DNA sayısı iki katına çıkar. Üç tur sonunda 1 × 2 × 2 × 2 = 8 DNA molekülü oluşur."},{"t":"Eski iplikleri izle","a":"Başta 2 eski iplik vardı","d":"Yarı korunumlu modele göre orijinal iplikler hiç kaybolmaz, sadece dağılır. Başlangıçtaki 2 eski iplik üç tur boyunca korunur."},{"t":"Eski iplikli molekülleri say","a":"2 molekülde orijinal iplik var","d":"Bu 2 eski iplik, sonunda 2 ayrı DNA molekülüne dağılır. Dolayısıyla 8 molekülden yalnızca 2 sinde orijinal eski iplik bulunur."}],"ans":"Toplam 8 molekül oluşur; bunların 2 sinde orijinal eski iplik bulunur."},{"q":"Meselson-Stahl deneyi yarı korunumlu modeli nasıl desteklemiştir, kısaca açıklayınız.","steps":[{"t":"Deneyin kurgusunu hatırla","a":"Ağır ve hafif azot kullanıldı","d":"Bakteriler önce ağır azotlu (¹⁵N) ortamda üretilip DNA ları ağırlaştırıldı, sonra hafif azotlu (¹⁴N) ortama aktarıldı. DNA nın yoğunluğu replikasyon sonrası ölçüldü."},{"t":"İlk kuşağı yorumla","a":"Tek ara yoğunluk çıktı","d":"Bir replikasyon sonrası tüm DNA, ağır ile hafifin ortasında tek bir ara yoğunlukta bulundu. Bu, her molekülün bir eski (ağır) bir yeni (hafif) iplikten oluştuğunu gösterdi."},{"t":"Modeli destekle","a":"Korunumlu model elendi","d":"Tamamen korunumlu model olsaydı ağır ve hafif olmak üzere iki ayrı bant çıkardı. Ara yoğunluğun tek bant vermesi yarı korunumlu modeli doğruladı."}],"ans":"İlk kuşakta tek ara yoğunluk çıkması, her DNA nın bir eski bir yeni iplik taşıdığını yani yarı korunumlu modeli kanıtladı."},{"q":"Bir bakteri ağır azotlu ortamda büyütülüp hafif azotlu ortamda iki kez replike olursa, oluşan 4 DNA molekülünden kaçı tamamen hafif iplik içerir?","steps":[{"t":"Başlangıç DNA sını belirle","a":"İki iplik de ağırdır","d":"Ağır azotlu ortamda büyüyen bakterinin DNA sında her iki iplik de ağır (¹⁵N) içerir. Hafif ortama geçince yeni iplikler hafif (¹⁴N) yapılır."},{"t":"İki replikasyonu izle","a":"2 ağır iplik 4 molekül arasında dağılır","d":"İki tur sonunda 4 DNA molekülü oluşur. Başlangıçtaki 2 ağır iplik bu moleküllerden ikisine birer tane dağılır, diğer ipliklerin tümü hafiftir."},{"t":"Tamamen hafif olanları say","a":"2 molekül sadece hafif iplik içerir","d":"Ağır iplik içeren 2 molekül melez (ağır+hafif) olur. Geriye kalan 2 molekülün her iki ipliği de hafiftir, yani tamamen hafiftir."}],"ans":"4 molekülün 2 si tamamen hafif iplik içerir."},{"q":"DNA polimeraz yalnızca 5'→3' yönünde sentez yapabilir. Bu durum öncü (leading) ve gecikmeli (lagging) iplik kavramlarını nasıl doğurur?","steps":[{"t":"Sentez yönü kısıtını yaz","a":"Polimeraz sadece 5'→3' uzatır","d":"DNA polimeraz yeni nükleotitleri yalnızca ipliğin 3' ucuna ekleyebilir, yani 5'→3' yönünde çalışır. Kalıbı ise 3'→5' yönünde okur."},{"t":"Çatalın iki kalıbını incele","a":"Kalıplar zıt yönlüdür","d":"Antiparalel yapı nedeniyle çatalda iki kalıp iplik zıt yönlerdedir. Bir kalıp çatal ilerleme yönüyle uyumlu, diğeri ters yöndedir."},{"t":"İki iplik tipini açıkla","a":"Öncü sürekli, gecikmeli parçalı","d":"Çatalla aynı yöndeki kalıp üzerinde sentez kesintisiz ilerler; buna öncü iplik denir. Ters yöndeki kalıpta sentez geriye doğru kısa parçalar (Okazaki) halinde yapılır; buna gecikmeli iplik denir."}],"ans":"Antiparalellik ve 5'→3' kısıtı nedeniyle bir iplik sürekli (öncü), diğeri parçalı (gecikmeli) sentezlenir."},{"q":"Bir DNA molekülünde 3000 baz çifti vardır. Bir kez replike olduğunda toplam kaç yeni nükleotit (baz) sentezlenir?","steps":[{"t":"Toplam baz sayısını bul","a":"3000 çift = 6000 baz","d":"Her baz çifti iki bazdan oluşur. 3000 baz çifti, ipliklerde toplam 3000 × 2 = 6000 baz demektir."},{"t":"Eski iplikleri ayır","a":"Eski ipliklerde 6000 baz korunur","d":"Yarı korunumlu modele göre iki eski iplik aynen korunur ve yeniden sentezlenmez. Bu 6000 baz olduğu gibi yeni moleküllere aktarılır."},{"t":"Yeni sentezleneni hesapla","a":"Yeni 2 iplik = 6000 baz","d":"Her yeni molekülde bir yeni iplik vardır; iki molekül için iki yeni iplik sentezlenir. Bu iki yeni iplik de toplam 6000 baz içerir, yani 6000 yeni nükleotit yapılır."}],"ans":"6000 yeni nükleotit (baz) sentezlenir."},{"q":"Replikasyon sırasında primer (başlatıcı) neden gereklidir?","steps":[{"t":"Polimerazın sınırını hatırla","a":"Serbest 3' uç gerektirir","d":"DNA polimeraz yeni nükleotidi ancak var olan bir zincirin serbest 3' ucuna ekleyebilir. Sentezi sıfırdan, boş kalıp üzerinde başlatamaz."},{"t":"Primerin rolünü açıkla","a":"Primer 3' uç sağlar","d":"Primer, kalıba eşlenen kısa bir RNA (veya nükleotit) parçasıdır ve serbest bir 3' uç oluşturur. Polimeraz bu uca eklenerek sentezi başlatır."},{"t":"Sonucu özetle","a":"Sentez başlatılabilir","d":"Primer olmadan polimerazın tutunup uzatabileceği bir başlangıç noktası bulunmaz. Bu yüzden replikasyonun başlaması için primer zorunludur."}],"ans":"Polimeraz serbest 3' uca ihtiyaç duyar; primer bu başlangıç ucunu sağlar."},{"q":"Eğer bir hücrede DNA polimerazın hata düzeltme (proofreading) işlevi bozulursa uzun vadede ne beklenir?","steps":[{"t":"Proofreading görevini hatırla","a":"Yanlış bazı tanır ve düzeltir","d":"DNA polimerazın hata düzeltme işlevi, eklenen yanlış nükleotidi fark edip çıkararak doğrusuyla değiştirir. Bu, replikasyon doğruluğunu büyük ölçüde artırır."},{"t":"Bozulma durumunu incele","a":"Hatalar düzeltilmeden kalır","d":"Proofreading bozulursa yanlış eklenen bazlar onarılmadan ipliğe yerleşir. Her replikasyonda hata oranı belirgin biçimde artar."},{"t":"Uzun vadeli sonucu açıkla","a":"Mutasyon birikimi artar","d":"Düzeltilmeyen hatalar sonraki turlarda kalıcılaşıp yeni mutasyonlara yol açar. Zamanla mutasyon yükü artar; bu da hücre işlev bozukluğu ve kanser gibi sonuçlara zemin hazırlayabilir."}],"ans":"Hata düzeltme olmayınca replikasyon hataları birikir; mutasyon oranı artar."},{"q":"Replikasyon orijinleri (başlangıç noktaları) ökaryot hücrelerde neden çok sayıda bulunur?","steps":[{"t":"Ökaryot DNA sını düşün","a":"DNA çok uzundur","d":"Ökaryot hücrelerde DNA çok uzun ve çok sayıda baz çifti içerir. Tek bir noktadan başlanırsa kopyalama çok uzun sürer."},{"t":"Çoklu orijinin etkisini incele","a":"Birçok çatal aynı anda çalışır","d":"Çok sayıda başlangıç noktası olunca DNA aynı anda birçok yerden açılır ve replikasyon çatalları paralel ilerler. Bu, kopyalama süresini büyük ölçüde kısaltır."},{"t":"Sonucu açıkla","a":"Replikasyon makul sürede biter","d":"Çoklu orijin sayesinde uzun DNA, hücre döngüsünün S evresine sığacak sürede kopyalanabilir. Tek orijin bu büyüklükte yetersiz kalırdı."}],"ans":"DNA çok uzun olduğundan, çok orijinle eşzamanlı kopyalama süreyi kısaltmak için gereklidir."},{"q":"Yarı korunumlu model yerine korunumlu model geçerli olsaydı, bir replikasyon sonrası oluşan iki DNA nın iplik yapısı nasıl olurdu?","steps":[{"t":"Korunumlu modeli tanımla","a":"Eski DNA bütün halde kalır","d":"Korunumlu modelde ana DNA nın iki ipliği hiç ayrılmadan birlikte korunur. Yeni DNA ise tamamen yeni iki iplikten sentezlenir."},{"t":"İki molekülü karşılaştır","a":"Biri tamamen eski, biri tamamen yeni","d":"Bu modele göre oluşan iki DNA dan biri yalnızca iki eski iplik, diğeri yalnızca iki yeni iplik içerirdi. Hiçbir molekülde eski-yeni karışımı olmazdı."},{"t":"Yarı korunumludan farkını söyle","a":"Karışık iplik yoktur","d":"Yarı korunumlu modelde her molekül bir eski bir yeni iplik taşırken, korunumlu modelde böyle bir karışım bulunmazdı. Meselson-Stahl deneyi tam da bu farkı test etmiştir."}],"ans":"Bir DNA tamamen eski, diğeri tamamen yeni iki iplikten oluşur; karışık iplikli molekül olmazdı."},{"q":"Bir hücredeki tek bir DNA molekülü n kez replike olursa oluşan molekül sayısını ve içlerinden orijinal iplik içerenlerin sayısını genelleyiniz.","steps":[{"t":"Molekül sayısını genelle","a":"2 üzeri n molekül","d":"Her replikasyon turunda molekül sayısı ikiye katlanır. n tur sonunda toplam 2 üzeri n DNA molekülü oluşur."},{"t":"Orijinal iplikleri izle","a":"Başta 2 orijinal iplik var","d":"Yarı korunumlu modele göre başlangıçtaki 2 eski iplik hiç kaybolmaz. Bu iplikler tüm turlar boyunca korunur ve dağılır."},{"t":"Orijinal iplikli molekülleri say","a":"Her zaman 2 molekül","d":"2 orijinal iplik en fazla 2 ayrı moleküle dağılabilir. Bu yüzden n kaç olursa olsun, orijinal iplik içeren molekül sayısı daima 2 dir."}],"ans":"Toplam 2 üzeri n molekül oluşur; orijinal iplik içerenlerin sayısı her zaman 2 dir."},{"q":"Gecikmeli iplikteki Okazaki parçalarının daha sonra tek bir sürekli iplik haline getirilmesi nasıl olur?","steps":[{"t":"Okazaki parçalarını hatırla","a":"Kısa parçalar halinde sentez","d":"Gecikmeli iplik, çatal ilerlemesine ters yönde kısa parçalar (Okazaki parçaları) halinde sentezlenir. Bu parçaların arasında kesiklikler kalır."},{"t":"Boşlukların doldurulmasını açıkla","a":"Primerler nükleotitle değiştirilir","d":"Her parçanın başındaki RNA primer çıkarılır ve yerine DNA nükleotitleri yerleştirilir. Böylece parçalar arasındaki RNA içerikli boşluklar DNA ile tamamlanır."},{"t":"Birleştirmeyi açıkla","a":"Ligaz parçaları birleştirir","d":"DNA ligaz enzimi komşu parçaların uçlarını birbirine bağlar. Bu bağlanma sonucunda kesik parçalar tek ve sürekli bir iplik haline gelir."}],"ans":"Primerler DNA ile değiştirilir, sonra DNA ligaz parçaları birleştirip sürekli iplik oluşturur."},{"q":"Replikasyon doğruluğu çok yüksek olmasına rağmen evrim için bir miktar hatanın (mutasyonun) faydalı olabileceğini açıklayınız.","steps":[{"t":"Doğruluğun önemini yaz","a":"Hatalar genelde zararlı","d":"Replikasyon yüksek doğrulukla çalışır; çünkü çoğu mutasyon proteinleri ve hücre işlevini bozar. Bu yüzden hata oranı çok düşük tutulur."},{"t":"Çeşitlilik kaynağını açıkla","a":"Mutasyon yeni varyasyon yaratır","d":"Buna karşın nadir mutasyonlar, popülasyonda yeni genetik çeşitlilik (varyasyon) oluşturur. Bu çeşitlilik kalıtsal olduğunda sonraki kuşaklara aktarılır."},{"t":"Evrime bağla","a":"Seçilim ham madde bulur","d":"Doğal seçilim, çevreye uyum sağlayan varyasyonları seçerek işler. Eğer hiç mutasyon olmasaydı yeni varyasyon doğmaz ve uzun vadede uyum sağlayıcı evrim için ham madde bulunmazdı."}],"ans":"Nadir mutasyonlar genetik çeşitlilik yaratır; doğal seçilim için ham madde sağlayarak evrime katkıda bulunur."},{"q":"Bir DNA da 1200 adenin ve 800 guanin varsa, bu molekülün bir kez replikasyonu için ortama hangi bazdan kaçar nükleotit eklenmesi gerekir?","steps":[{"t":"Çift iplik baz sayılarını bul","a":"A=T=1200, G=C=800","d":"Çift iplikli DNA da adenin timine, guanin sitozine eşittir. 1200 adenin için 1200 timin, 800 guanin için 800 sitozin vardır."},{"t":"Yeni ipliklerin ihtiyacını düşün","a":"Eski iplikler korunur, yeni iplikler kurulur","d":"Yarı korunumlu modelde eski ipliklerdeki bazlar yeniden yapılmaz. Yeni sentezlenen iki iplik, toplamda eski molekülün tüm bazları kadar nükleotit gerektirir."},{"t":"Her baz için sayıyı yaz","a":"A:1200, T:1200, G:800, C:800","d":"Yeni iplikler eski molekülün baz bileşimini birebir tekrarlar. Bu yüzden ortama 1200 adenin, 1200 timin, 800 guanin ve 800 sitozin nükleotidi eklenmesi gerekir."}],"ans":"1200 adenin, 1200 timin, 800 guanin ve 800 sitozin nükleotidi gerekir."},{"q":"Lineer (doğrusal) ökaryot kromozomlarında uç bölgelerin (telomer) her replikasyonda kısalma sorunu neden ortaya çıkar?","steps":[{"t":"Gecikmeli iplik sorununu hatırla","a":"Uçta primer boşluğu kalır","d":"Gecikmeli iplik primerlerle parçalar halinde sentezlenir. Doğrusal kromozomun en ucundaki son primer çıkarıldığında, yerini dolduracak serbest 3' uç bulunmaz."},{"t":"Boşluğun sonucunu açıkla","a":"Uç tam kopyalanamaz","d":"Polimeraz bu uç boşluğu dolduramadığı için yeni iplik kalıptan biraz kısa kalır. Böylece her replikasyonda kromozom ucu bir miktar kısalır."},{"t":"Telomerin rolünü söyle","a":"Telomer tampon görevi görür","d":"Telomerler, gen taşımayan tekrarlı uç dizileridir ve bu kısalmada feda edilerek genleri korur. Yine de bölünmeler sürdükçe telomerler kısalır ve bu hücre yaşlanmasıyla ilişkilidir."}],"ans":"Gecikmeli iplikte uçtaki son primer boşluğu doldurulamadığından, her replikasyonda telomer biraz kısalır."},{"q":"Replikasyon, mayoz öncesinde de bir kez gerçekleşir; ancak mayozda hücre iki kez bölünür. Bu durumun sonucu ne olur?","steps":[{"t":"Replikasyon sayısını yaz","a":"DNA bir kez kopyalanır","d":"Mayoz başlamadan önce, tıpkı mitozda olduğu gibi DNA yalnızca bir kez (S evresinde) replike olur. Böylece kromozom sayısı geçici olarak iki katına eşdeğer DNA içeriği oluşur."},{"t":"İki bölünmeyi düşün","a":"Bir kopya, iki bölünmeye paylaşılır","d":"Mayozda hücre arka arkaya iki kez bölünür ama arada yeni bir replikasyon olmaz. Tek replikasyonla elde edilen DNA, iki bölünme arasında paylaştırılır."},{"t":"Sonucu açıkla","a":"Kromozom sayısı yarıya iner","d":"Bir replikasyona karşılık iki bölünme olunca, oluşan dört hücrenin her birine ana hücrenin yarısı kadar kromozom düşer. Böylece haploit (n) gametler oluşur ve döllenmede sayı yeniden eşitlenir."}],"ans":"Tek replikasyona karşılık iki bölünme olduğundan kromozom sayısı yarıya iner; haploit gametler oluşur."}]}}};
